// src/contexts/AdminAuthContext.tsx
import React, { createContext, useContext, useEffect, useState, useCallback } from 'react';
import { adminApi } from '@/lib/api';

interface Admin {
  id: string;
  email: string;
  area_assigned: string;
}

interface AdminAuthContextType {
  admin: Admin | null;
  loading: boolean;
  login: (email: string, password: string) => Promise<void>;
  logout: () => Promise<void>;
  refreshAdmin: () => Promise<void>;
}

const AdminAuthContext = createContext<AdminAuthContextType | null>(null);

export function AdminAuthProvider({ children }: { children: React.ReactNode }) {
  const [admin, setAdmin] = useState<Admin | null>(null);
  const [loading, setLoading] = useState(true);

  const refreshAdmin = useCallback(async () => {
    try {
      const res = await adminApi.me();
      setAdmin(res.admin);
    } catch {
      setAdmin(null);
    }
  }, []);

  useEffect(() => {
    refreshAdmin().finally(() => setLoading(false));
  }, [refreshAdmin]);

  const login = async (email: string, password: string) => {
    const res = await adminApi.login({ email, password });
    setAdmin(res.admin);
  };

  const logout = async () => {
    await adminApi.logout();
    setAdmin(null);
  };

  return (
    <AdminAuthContext.Provider value={{ admin, loading, login, logout, refreshAdmin }}>
      {children}
    </AdminAuthContext.Provider>
  );
}

export function useAdminAuth() {
  const ctx = useContext(AdminAuthContext);
  if (!ctx) throw new Error('useAdminAuth must be used within AdminAuthProvider');
  return ctx;
}

// src/contexts/AuthContext.tsx
import React, {
  createContext, useContext, useEffect, useState, useCallback,
} from 'react';
import { authApi } from '@/lib/api';

interface User {
  id: string;
  name: string;
  email?: string;
  role?: string;
}

interface Shg {
  id: string;
  name: string;
  village?: string;
  district?: string;
  [key: string]: unknown;
}

interface AuthContextType {
  user: User | null;
  shg: Shg | null;
  onboarded: boolean;
  loading: boolean;
  login: (email: string, password: string) => Promise<void>;
  memberLogin: (name: string, password: string) => Promise<void>;
  signup: (name: string, email: string, password: string) => Promise<void>;
  memberSignup: (name: string, phone: string, aadhar: string, shg_id: string, password: string) => Promise<void>;
  logout: () => Promise<void>;
  refreshUser: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | null>(null);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [shg, setShg] = useState<Shg | null>(null);
  const [onboarded, setOnboarded] = useState(false);
  const [loading, setLoading] = useState(true);

  const refreshUser = useCallback(async () => {
    try {
      const res = await authApi.me();
      setUser(res.user);
      setShg(res.shg);
      setOnboarded(res.onboarded);
    } catch {
      setUser(null);
      setShg(null);
      setOnboarded(false);
    }
  }, []);

  useEffect(() => {
    refreshUser().finally(() => setLoading(false));
  }, [refreshUser]);

  const login = async (email: string, password: string) => {
    const res = await authApi.login({ email, password });
    setUser(res.user);
    setOnboarded(res.onboarded);
    if (res.onboarded) await refreshUser();
  };

  const signup = async (name: string, email: string, password: string) => {
    const res = await authApi.signup({ name, email, password });
    setUser(res.user);
    setOnboarded(false);
  };

  const memberSignup = async (name: string, phone: string, aadhar: string, shg_id: string, password: string) => {
    const res = await authApi.memberSignup({ name, phone, aadhar, shg_id, password });
    setUser(res.user);
    setOnboarded(true);
  };

  const memberLogin = async (name: string, password: string) => {
    const res = await authApi.memberLogin({ name, password });
    setUser(res.user);
    setOnboarded(true); // Members don't have an onboarding flow, they are part of an SHG
  };

  const logout = async () => {
    await authApi.logout();
    setUser(null);
    setShg(null);
    setOnboarded(false);
  };

  return (
    <AuthContext.Provider value={{ user, shg, onboarded, loading, login, memberLogin, signup, memberSignup, logout, refreshUser }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
  return ctx;
}

