};
type EditForm = typeof EMPTY_EDIT;

// EditMemberForm — outside main component to prevent focus loss
function EditMemberForm({ form, setForm }: { form: EditForm; setForm: React.Dispatch<React.SetStateAction<EditForm>> }) {
  return (
    <div className="space-y-6">
      <div>
        <p className="text-xs font-semibold text-[#C2185B] uppercase tracking-wider mb-3">Personal Details</p>
        <div className="grid grid-cols-2 gap-3">
          <div className="col-span-2 space-y-1"><Label>Full Name *</Label>
            <Input value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))} required /></div>
          <div className="space-y-1"><Label>Husband's Name</Label>
            <Input value={form.husband_name} onChange={e=>setForm(f=>({...f,husband_name:e.target.value}))} placeholder="W/O" /></div>
          <div className="space-y-1"><Label>Phone</Label>
            <Input value={form.phone} onChange={e=>setForm(f=>({...f,phone:e.target.value}))} maxLength={10} /></div>
          <div className="space-y-1"><Label>Age</Label>
            <Input type="number" value={form.age} onChange={e=>setForm(f=>({...f,age:e.target.value}))} min={18} max={80} /></div>
          <div className="space-y-1"><Label>Aadhaar</Label>
            <Input value={form.aadhar} onChange={e=>setForm(f=>({...f,aadhar:e.target.value}))} maxLength={12} /></div>
          <div className="space-y-1"><Label>Occupation</Label>
            <Input value={form.occupation} onChange={e=>setForm(f=>({...f,occupation:e.target.value}))} placeholder="e.g. Dairy, Tailoring" /></div>
          <div className="space-y-1"><Label>Monthly Income (₹)</Label>
            <Input type="number" value={form.income} onChange={e=>setForm(f=>({...f,income:e.target.value}))} /></div>
        </div>
      </div>
      <div>
        <p className="text-xs font-semibold text-[#C2185B] uppercase tracking-wider mb-3">Address</p>
        <div className="grid grid-cols-2 gap-3">
          <div className="space-y-1"><Label>Village</Label>
            <Input value={form.village} onChange={e=>setForm(f=>({...f,village:e.target.value}))} /></div>
          <div className="space-y-1"><Label>Gram Panchayat</Label>
            <Input value={form.gram_panchayat} onChange={e=>setForm(f=>({...f,gram_panchayat:e.target.value}))} /></div>
          <div className="space-y-1"><Label>Block / Tehsil</Label>
            <Input value={form.block} onChange={e=>setForm(f=>({...f,block:e.target.value}))} /></div>
          <div className="space-y-1"><Label>District</Label>
            <Input value={form.district} onChange={e=>setForm(f=>({...f,district:e.target.value}))} /></div>
          <div className="space-y-1"><Label>State</Label>
            <Input value={form.state} onChange={e=>setForm(f=>({...f,state:e.target.value}))} /></div>
          <div className="space-y-1"><Label>PIN Code</Label>
            <Input value={form.pin_code} onChange={e=>setForm(f=>({...f,pin_code:e.target.value}))} maxLength={6} /></div>
        </div>
      </div>
      <div>
        <p className="text-xs font-semibold text-[#C2185B] uppercase tracking-wider mb-3">Group & Bank</p>
        <div className="grid grid-cols-2 gap-3">
          <div className="space-y-1"><Label>Role in Group</Label>
            <Select value={form.role} onValueChange={v=>setForm(f=>({...f,role:v as any}))}>
              <SelectTrigger><SelectValue /></SelectTrigger>
              <SelectContent>{ROLES.map(r=><SelectItem key={r} value={r}>{ROLE_LABELS[r]}</SelectItem>)}</SelectContent>
            </Select></div>
          <div className="space-y-1"><Label>Joining Date</Label>
            <Input type="date" value={form.joined_date} onChange={e=>setForm(f=>({...f,joined_date:e.target.value}))} /></div>
          <div className="space-y-1"><Label>Bank Account No.</Label>
            <Input value={form.bank_account} onChange={e=>setForm(f=>({...f,bank_account:e.target.value}))} placeholder="PMJDY account" /></div>
          <div className="space-y-1"><Label>Bank IFSC</Label>
            <Input value={form.bank_ifsc} onChange={e=>setForm(f=>({...f,bank_ifsc:e.target.value}))} /></div>
          <div className="space-y-1"><Label>Caste Category</Label>
            <Select value={form.caste_category} onValueChange={v=>setForm(f=>({...f,caste_category:v as any}))}>
              <SelectTrigger><SelectValue placeholder="Select" /></SelectTrigger>
              <SelectContent>{CASTE_CATEGORIES.map(c=><SelectItem key={c} value={c}>{c.toUpperCase()}</SelectItem>)}</SelectContent>
            </Select></div>
          <div className="space-y-1"><Label>BPL Status</Label>
            <div className="flex gap-2 mt-1">
              <button type="button" onClick={()=>setForm(f=>({...f,bpl_status:true}))}
                className={`flex-1 py-2 rounded-lg border text-sm font-medium transition-colors ${form.bpl_status?"bg-orange-50 border-orange-300 text-orange-700":"border-gray-200 text-gray-500"}`}>BPL</button>
              <button type="button" onClick={()=>setForm(f=>({...f,bpl_status:false}))}
                className={`flex-1 py-2 rounded-lg border text-sm font-medium transition-colors ${!form.bpl_status?"bg-gray-50 border-gray-300 text-gray-700":"border-gray-200 text-gray-500"}`}>Non-BPL</button>
            </div></div>
          <div className="col-span-2 space-y-1"><Label>Member Status</Label>
            <div className="flex gap-2 mt-1">
              <button type="button" onClick={()=>setForm(f=>({...f,status:"active"}))}
                className={`flex-1 py-2 rounded-lg border text-sm font-medium transition-colors ${form.status==="active"?"bg-green-50 border-green-300 text-green-700":"border-gray-200 text-gray-500"}`}>Active</button>
              <button type="button" onClick={()=>setForm(f=>({...f,status:"inactive"}))}
                className={`flex-1 py-2 rounded-lg border text-sm font-medium transition-colors ${form.status==="inactive"?"bg-red-50 border-red-300 text-red-600":"border-gray-200 text-gray-500"}`}>Inactive</button>
            </div></div>
        </div>
      </div>
    </div>
  );
}

export default function MemberProfile() {
  const { memberId } = useParams<{ memberId: string }>();
  const [member, setMember]                 = useState<any>(null);
  const [savings, setSavings]               = useState<any[]>([]);
  const [loans, setLoans]                   = useState<any[]>([]);
  const [loanRepayments, setLoanRepayments] = useState<Record<string,any[]>>({});
  const [loading, setLoading]               = useState(true);
  const [activeTab, setActiveTab]           = useState<Tab>("overview");
  const [showEdit, setShowEdit]             = useState(false);
  const [editForm, setEditForm]             = useState<EditForm>({...EMPTY_EDIT});
  const [editSaving, setEditSaving]         = useState(false);

  useEffect(()=>{ if(memberId) loadAll(memberId); },[memberId]);

  async function loadAll(id:string) {
    setLoading(true);
    try {
      const [mRes, sRes, lRes] = await Promise.all([
        membersApi.get(id), savingsApi.list({member_id:id}), loansApi.list({member_id:id}),
      ]);
      setMember(mRes.data);
      setSavings(sRes.data||[]);
      const ml = lRes.data||[];
      setLoans(ml);
      const repMap:Record<string,any[]>={};
      await Promise.all(ml.map(async(loan:any)=>{
        try { const r=await repaymentsApi.list({loan_id:loan.id}); repMap[loan.id]=r.data||[]; }
        catch { repMap[loan.id]=[]; }
      }));
      setLoanRepayments(repMap);
    } catch(err:any){ toast.error(err.message||"Failed to load member"); }
    finally { setLoading(false); }
  }

  function openEdit() {
    if(!member) return;
    setEditForm({
      name:member.name||"", phone:member.phone||"", age:member.age?String(member.age):"",
      income:member.income?String(member.income):"", aadhar:member.aadhar||"",
      husband_name:member.husband_name||"", occupation:member.occupation||"",
      village:member.village||"", gram_panchayat:member.gram_panchayat||"",
      block:member.block||"", district:member.district||"", state:member.state||"", pin_code:member.pin_code||"",
      role:member.role||"member", joined_date:member.joined_date?member.joined_date.split("T")[0]:"",
      status:member.status||"active", bank_account:member.bank_account||"", bank_ifsc:member.bank_ifsc||"",
      caste_category:member.caste_category||"", bpl_status:member.bpl_status||false,
    });
    setShowEdit(true);
  }

  async function handleEdit(e:React.FormEvent) {
    e.preventDefault();
    if(!member) return;
    setEditSaving(true);
    try {
      await membersApi.update(member.id, {
        ...editForm, age:editForm.age?Number(editForm.age):null, income:editForm.income?Number(editForm.income):null,
      });
      toast.success("Profile updated!");
      setShowEdit(false);
      loadAll(member.id);
    } catch(err:any){ toast.error(err.message||"Failed to update"); }
    finally { setEditSaving(false); }
  }

  const totalSavings     = savings.reduce((s,r)=>s+Number(r.amount),0);
  const activeLoans      = loans.filter(l=>l.status==="active");
  const totalOutstanding = activeLoans.reduce((s,l)=>s+Number(l.loan_amount),0);
  const loanEligibility  = totalSavings * 5;

  function getRepStats(loanId:string) {
    const reps = loanRepayments[loanId]||[];
    const paid = reps.filter(r=>r.status==="paid").length;
    const total = reps.length;
    const overdue = reps.filter(r=>r.status==="overdue").length;
    return { paid, total, overdue, pct: total?Math.round((paid/total)*100):0 };
  }

  if(loading) return (
    <DashboardLayout>
      <div className="flex justify-center py-24">
        <div className="w-8 h-8 rounded-full border-4 border-[#C2185B]/30 border-t-[#C2185B] animate-spin"/>
      </div>
    </DashboardLayout>
  );

  if(!member) return (
    <DashboardLayout>
      <div className="text-center py-24">
        <User className="w-12 h-12 mx-auto text-muted-foreground/30 mb-4"/>
        <p className="text-muted-foreground font-medium">Member not found</p>
        <Button asChild className="mt-4" variant="outline"><Link to="/members">← Back to Members</Link></Button>
      </div>
    </DashboardLayout>
  );

  return (
    <DashboardLayout>
      <Link to="/members" className="inline-flex items-center gap-1.5 text-sm text-muted-foreground hover:text-foreground mb-5 transition-colors">
        <ArrowLeft className="w-4 h-4"/> Back to Members
      </Link>

      {/* Hero Header */}
      <div className="relative rounded-2xl overflow-hidden mb-6 border border-[#C2185B]/10 shadow-sm">
        <div className="h-24 bg-gradient-to-r from-[#C2185B] to-[#6A1B9A]"/>
        <div className="bg-white px-6 pb-6">
          <div className="flex flex-col sm:flex-row sm:items-end gap-4 -mt-10">
            <div className="w-20 h-20 rounded-2xl bg-gradient-to-br from-[#C2185B] to-[#6A1B9A] border-4 border-white shadow-md flex items-center justify-center shrink-0">
              <span className="text-white text-3xl font-bold">{member.name.charAt(0).toUpperCase()}</span>
            </div>
            <div className="flex-1 sm:pb-1">
              <div className="flex items-center gap-2 flex-wrap">
                <h1 className="text-2xl font-bold text-gray-900">{member.name}</h1>
                <span className={`text-xs px-2.5 py-0.5 rounded-full font-medium border ${ROLE_COLORS[member.role]||ROLE_COLORS.member}`}>
                  {ROLE_LABELS[member.role]||"Member"}
                </span>
                <span className={`text-xs px-2.5 py-0.5 rounded-full font-medium ${member.status==="active"?"bg-green-100 text-green-700":"bg-gray-100 text-gray-500"}`}>
                  {member.status==="active"?"● Active":"○ Inactive"}
                </span>
              </div>
              <div className="flex flex-wrap items-center gap-x-4 gap-y-1 mt-1.5 text-sm text-muted-foreground">
                {member.husband_name && <span>W/O {member.husband_name}</span>}
                {member.village && <span className="flex items-center gap-1"><MapPin className="w-3.5 h-3.5"/>{[member.village,member.block,member.district].filter(Boolean).join(", ")}</span>}
                {member.phone && <span className="flex items-center gap-1"><Phone className="w-3.5 h-3.5"/>{member.phone}</span>}
                {member.joined_date && <span className="flex items-center gap-1"><Calendar className="w-3.5 h-3.5"/>Joined {new Date(member.joined_date).toLocaleDateString("en-IN",{day:"numeric",month:"short",year:"numeric"})}</span>}
              </div>
              <div className="flex flex-wrap gap-2 mt-2">
                {member.occupation && <span className="text-xs bg-[#C2185B]/5 text-[#C2185B] px-2.5 py-0.5 rounded-full">{member.occupation}</span>}
                {member.caste_category && <span className="text-xs bg-gray-100 text-gray-600 px-2.5 py-0.5 rounded-full uppercase">{member.caste_category}</span>}
                {member.bpl_status && <span className="text-xs bg-orange-100 text-orange-700 px-2.5 py-0.5 rounded-full">BPL</span>}
                {member.age && <span className="text-xs bg-gray-100 text-gray-600 px-2.5 py-0.5 rounded-full">Age {member.age}</span>}
              </div>
            </div>
            <Button onClick={openEdit} variant="outline" className="border-[#C2185B]/30 text-[#C2185B] hover:bg-[#C2185B]/5 shrink-0">
              <Pencil className="w-4 h-4 mr-1.5"/> Edit Profile
            </Button>
          </div>
        </div>
      </div>

      {/* Stat Cards */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
        {[
          { icon:PiggyBank, color:"#C2185B", label:"Total Savings", value:`₹${totalSavings.toLocaleString("en-IN")}`, sub:`${savings.length} contributions` },
          { icon:TrendingUp, color:"#6A1B9A", label:"Loan Eligibility", value:`₹${loanEligibility.toLocaleString("en-IN")}`, sub:"5× total savings" },
          { icon:Landmark, color:"#0288D1", label:"Active Loans", value:activeLoans.length, sub:activeLoans.length?`₹${totalOutstanding.toLocaleString("en-IN")} outstanding`:"No active loans" },
          { icon:BadgeCheck, color:"#388E3C", label:"Loans Taken", value:loans.length, sub:`${loans.filter(l=>l.status==="closed").length} fully repaid` },
        ].map(({icon:Icon,color,label,value,sub})=>(
          <Card key={label} className="border-border/60 shadow-sm">
            <CardContent className="pt-4 pb-4">
              <div className="flex items-start gap-3">
                <div className="w-9 h-9 rounded-xl flex items-center justify-center shrink-0" style={{backgroundColor:`${color}15`}}>
                  <Icon className="w-4 h-4" style={{color}}/>
                </div>
                <div>
                  <p className="text-xs text-muted-foreground">{label}</p>
                  <p className="text-xl font-bold text-gray-900 leading-tight">{value}</p>
                  <p className="text-xs text-muted-foreground">{sub}</p>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Tabs */}
      <div className="flex gap-1 bg-gray-100 rounded-xl p-1 mb-6 w-fit">
        {(["overview","savings","loans"] as Tab[]).map(tab=>(
          <button key={tab} onClick={()=>setActiveTab(tab)}
            className={`px-5 py-2 rounded-lg text-sm font-medium capitalize transition-all ${activeTab===tab?"bg-white shadow text-[#C2185B]":"text-muted-foreground hover:text-foreground"}`}>
            {tab}
          </button>
        ))}
      </div>

      {/* OVERVIEW */}
      {activeTab==="overview" && (
        <div className="grid lg:grid-cols-2 gap-5">
          {/* Personal Info */}
          <Card className="border-border/60">
            <CardHeader className="pb-3">
              <CardTitle className="text-sm font-semibold flex items-center gap-2">
                <div className="w-7 h-7 rounded-lg bg-[#C2185B]/10 flex items-center justify-center"><User className="w-3.5 h-3.5 text-[#C2185B]"/></div>
                Personal Information
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-0">
              {[
                {label:"Full Name", value:member.name},
                {label:"W/O (Husband)", value:member.husband_name||"—"},
                {label:"Age", value:member.age?`${member.age} years`:"—"},
                {label:"Aadhaar", value:member.aadhar?`XXXX XXXX ${member.aadhar.slice(-4)}`:"—"},
                {label:"Occupation", value:member.occupation||"—"},
                {label:"Monthly Income", value:member.income?`₹${Number(member.income).toLocaleString("en-IN")}`:"—"},
                {label:"Caste Category", value:member.caste_category?member.caste_category.toUpperCase():"—"},
                {label:"BPL Status", value:member.bpl_status?"Yes (BPL)":"No"},
              ].map(({label,value})=>(
                <div key={label} className="flex justify-between items-center py-2.5 border-b border-gray-50 last:border-0 text-sm">
                  <span className="text-muted-foreground w-36 shrink-0">{label}</span>
                  <span className="font-medium text-gray-800 text-right">{value}</span>
                </div>
              ))}
            </CardContent>
          </Card>

          {/* Address */}
          <Card className="border-border/60">
            <CardHeader className="pb-3">
              <CardTitle className="text-sm font-semibold flex items-center gap-2">
                <div className="w-7 h-7 rounded-lg bg-[#6A1B9A]/10 flex items-center justify-center"><Home className="w-3.5 h-3.5 text-[#6A1B9A]"/></div>
                Address Details
              </CardTitle>
            </CardHeader>
            <CardContent>
              {[
                {label:"Village", value:member.village||"—"},
                {label:"Gram Panchayat", value:member.gram_panchayat||"—"},
                {label:"Block / Tehsil", value:member.block||"—"},
                {label:"District", value:member.district||"—"},
                {label:"State", value:member.state||"—"},
                {label:"PIN Code", value:member.pin_code||"—"},
              ].map(({label,value})=>(
                <div key={label} className="flex justify-between items-center py-2.5 border-b border-gray-50 last:border-0 text-sm">
                  <span className="text-muted-foreground w-36 shrink-0">{label}</span>
                  <span className="font-medium text-gray-800 text-right">{value}</span>
                </div>
              ))}
              {(member.village||member.block||member.district) && (
                <div className="mt-3 p-3 bg-gray-50 rounded-xl text-sm text-gray-600 leading-relaxed">
                  <MapPin className="w-3.5 h-3.5 inline mr-1 text-[#C2185B]"/>
                  {[member.village,member.gram_panchayat,member.block,member.district,member.state,member.pin_code].filter(Boolean).join(", ")}
                </div>
              )}
            </CardContent>
          </Card>

          {/* Group Info */}
          <Card className="border-border/60">
            <CardHeader className="pb-3">
              <CardTitle className="text-sm font-semibold flex items-center gap-2">
                <div className="w-7 h-7 rounded-lg bg-green-50 flex items-center justify-center"><Shield className="w-3.5 h-3.5 text-green-600"/></div>
                Group Details
              </CardTitle>
            </CardHeader>
            <CardContent>
              {[
                {label:"Role", value:ROLE_LABELS[member.role]||"Member"},
                {label:"Status", value:member.status==="active"?"Active":"Inactive"},
                {label:"Joined", value:member.joined_date?new Date(member.joined_date).toLocaleDateString("en-IN",{day:"numeric",month:"long",year:"numeric"}):"—"},
                {label:"Tenure", value:member.joined_date?(()=>{
                  const months=Math.floor((Date.now()-new Date(member.joined_date).getTime())/(1000*60*60*24*30));
                  return months>=12?`${Math.floor(months/12)} yr ${months%12} mo`:`${months} months`;
                })():"—"},
              ].map(({label,value})=>(
                <div key={label} className="flex justify-between items-center py-2.5 border-b border-gray-50 last:border-0 text-sm">
                  <span className="text-muted-foreground w-36 shrink-0">{label}</span>
                  <span className="font-medium text-gray-800 text-right">{value}</span>
                </div>
              ))}
            </CardContent>
          </Card>

          {/* Bank + Eligibility */}
          <Card className="border-border/60">
            <CardHeader className="pb-3">
              <CardTitle className="text-sm font-semibold flex items-center gap-2">
                <div className="w-7 h-7 rounded-lg bg-blue-50 flex items-center justify-center"><Building2 className="w-3.5 h-3.5 text-blue-600"/></div>
                Bank Details (PMJDY)
              </CardTitle>
            </CardHeader>
            <CardContent>
              {[
                {label:"Account No.", value:member.bank_account?`XXXX XXXX ${member.bank_account.slice(-4)}`:"—"},
                {label:"IFSC Code", value:member.bank_ifsc||"—"},
              ].map(({label,value})=>(
                <div key={label} className="flex justify-between items-center py-2.5 border-b border-gray-50 text-sm">
                  <span className="text-muted-foreground w-36 shrink-0">{label}</span>
                  <span className="font-medium text-gray-800 font-mono text-right">{value}</span>
                </div>
              ))}
              <div className="mt-4 rounded-xl bg-gradient-to-r from-[#C2185B]/5 to-[#6A1B9A]/5 border border-[#C2185B]/10 p-4">
                <p className="text-xs text-muted-foreground mb-0.5">Maximum Loan Eligibility</p>
                <p className="text-2xl font-bold text-[#C2185B]">₹{loanEligibility.toLocaleString("en-IN")}</p>
                <p className="text-xs text-muted-foreground mt-1">
                  Based on ₹{totalSavings.toLocaleString("en-IN")} savings × 5
                  {activeLoans.length>0&&` · ₹${totalOutstanding.toLocaleString("en-IN")} currently borrowed`}
                </p>
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* SAVINGS */}
      {activeTab==="savings" && (
        <Card className="border-border/60">
          <CardHeader className="pb-3">
            <div className="flex items-center justify-between flex-wrap gap-2">
              <CardTitle className="text-base flex items-center gap-2">
                <PiggyBank className="w-4 h-4 text-[#C2185B]"/> Savings History
              </CardTitle>
              <div className="flex items-center gap-4 text-sm">
                <span className="text-muted-foreground">{savings.length} entries</span>
                <span className="font-semibold text-[#C2185B]">Total: ₹{totalSavings.toLocaleString("en-IN")}</span>
              </div>
            </div>
          </CardHeader>
          <CardContent>
            {savings.length===0?(
              <div className="text-center py-16 text-muted-foreground">
                <PiggyBank className="w-10 h-10 mx-auto mb-2 opacity-20"/><p>No savings recorded yet</p>
              </div>
            ):(
              <>
                {/* Bar chart */}
                <div className="mb-5 p-4 bg-gray-50 rounded-xl">
                  <p className="text-xs text-muted-foreground mb-3">Monthly Contributions (last 12)</p>
                  <div className="flex items-end gap-1.5 h-16">
                    {savings.slice(-12).map((s,i)=>{
                      const max=Math.max(...savings.slice(-12).map((x:any)=>Number(x.amount)));
                      const pct=max?(Number(s.amount)/max)*100:0;
                      return (
                        <div key={i} className="flex-1 flex flex-col items-center gap-1 group relative">
                          <div className="w-full rounded-t bg-gradient-to-t from-[#C2185B] to-[#6A1B9A]" style={{height:`${Math.max(pct,6)}%`}}/>
                          <span className="text-[9px] text-muted-foreground">{MONTH_NAMES[s.month]}</span>
                          <div className="absolute -top-7 left-1/2 -translate-x-1/2 bg-gray-800 text-white text-[9px] px-1.5 py-0.5 rounded opacity-0 group-hover:opacity-100 whitespace-nowrap pointer-events-none">
                            ₹{Number(s.amount).toLocaleString("en-IN")}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
                <div className="overflow-x-auto">
                  <Table>
                    <TableHeader>
                      <TableRow className="bg-gray-50">
                        <TableHead>Month</TableHead><TableHead>Amount</TableHead>
                        <TableHead>Mode</TableHead><TableHead>Date</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {savings.map(s=>(
                        <TableRow key={s.id} className="hover:bg-gray-50/50">
                          <TableCell className="font-medium">{MONTH_NAMES[s.month]} {s.year}</TableCell>
                          <TableCell><span className="font-semibold text-green-700">₹{Number(s.amount).toLocaleString("en-IN")}</span></TableCell>
                          <TableCell><span className="text-xs capitalize bg-gray-100 text-gray-600 px-2 py-0.5 rounded-full">{s.payment_mode}</span></TableCell>
                          <TableCell className="text-muted-foreground text-sm">{s.date?new Date(s.date).toLocaleDateString("en-IN",{day:"numeric",month:"short",year:"numeric"}):"—"}</TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </div>
                <div className="mt-4 p-3 bg-[#C2185B]/5 rounded-xl flex justify-between items-center">
                  <span className="text-sm text-muted-foreground">Running Total</span>
                  <span className="text-lg font-bold text-[#C2185B]">₹{totalSavings.toLocaleString("en-IN")}</span>
                </div>
              </>
            )}
          </CardContent>
        </Card>
      )}

      {/* LOANS */}
      {activeTab==="loans" && (
        <div className="space-y-4">
          {loans.length===0?(
            <Card className="border-border/60">
              <CardContent className="py-16 text-center text-muted-foreground">
                <Landmark className="w-10 h-10 mx-auto mb-2 opacity-20"/><p>No loans taken yet</p>
              </CardContent>
            </Card>
          ):loans.map(loan=>{
            const {paid,total,overdue,pct}=getRepStats(loan.id);
            const reps=loanRepayments[loan.id]||[];
            return (
              <Card key={loan.id} className="border-border/60">
                <CardContent className="pt-5">
                  <div className="flex items-start justify-between gap-3 mb-4">
                    <div>
                      <p className="font-semibold text-gray-900 text-base">{loan.purpose||"General Purpose"}</p>
                      <div className="flex flex-wrap gap-3 mt-1 text-sm text-muted-foreground">
                        <span className="flex items-center gap-1"><IndianRupee className="w-3 h-3"/>₹{Number(loan.loan_amount).toLocaleString("en-IN")}</span>
                        <span>{loan.interest_rate}% p.m.</span>
                        <span>{loan.tenure_months} months</span>
                        {loan.disbursed_date&&<span className="flex items-center gap-1"><Calendar className="w-3 h-3"/>{new Date(loan.disbursed_date).toLocaleDateString("en-IN",{day:"numeric",month:"short",year:"numeric"})}</span>}
                      </div>
                    </div>
                    <span className={`text-xs px-2.5 py-1 rounded-full font-medium shrink-0 ${loan.status==="active"?"bg-blue-100 text-blue-700":loan.status==="closed"?"bg-green-100 text-green-700":"bg-red-100 text-red-600"}`}>
                      {loan.status.charAt(0).toUpperCase()+loan.status.slice(1)}
                    </span>
                  </div>
                  <div className="mb-4">
                    <div className="flex justify-between text-xs text-muted-foreground mb-1.5">
                      <span>{paid} of {total} EMIs paid</span>
                      <span className="font-medium">{pct}% repaid</span>
                    </div>
                    <div className="h-2.5 bg-gray-100 rounded-full overflow-hidden">
                      <div className={`h-full rounded-full ${loan.status==="closed"?"bg-green-500":"bg-gradient-to-r from-[#C2185B] to-[#6A1B9A]"}`} style={{width:`${pct}%`}}/>
                    </div>
                  </div>
                  {overdue>0&&(
                    <div className="flex items-center gap-1.5 text-xs text-red-600 bg-red-50 border border-red-100 rounded-lg px-3 py-2 mb-4">
                      <AlertCircle className="w-3.5 h-3.5 shrink-0"/>
                      {overdue} overdue EMI{overdue>1?"s":""} — immediate attention required
                    </div>
                  )}
                  {reps.length>0&&(
                    <div className="border-t pt-4">
                      <p className="text-xs font-medium text-muted-foreground mb-3">EMI Schedule</p>
                      <div className="space-y-2 max-h-56 overflow-y-auto pr-1">
                        {reps.map(r=>(
                          <div key={r.id} className="flex items-center justify-between py-1.5 px-3 rounded-lg bg-gray-50/80 text-sm">
                            <div className="flex items-center gap-2">
                              {r.status==="paid"&&<CheckCircle2 className="w-4 h-4 text-green-500 shrink-0"/>}
                              {r.status==="overdue"&&<AlertCircle className="w-4 h-4 text-red-500 shrink-0"/>}
                              {r.status==="pending"&&<Clock className="w-4 h-4 text-amber-500 shrink-0"/>}
                              <span className="text-muted-foreground">Due {new Date(r.due_date).toLocaleDateString("en-IN",{day:"numeric",month:"short",year:"numeric"})}</span>
                            </div>
                            <div className="flex items-center gap-3">
                              <span className="font-medium">₹{Number(r.emi_amount).toLocaleString("en-IN")}</span>
                              {r.paid_date&&<span className="text-xs text-green-600">Paid {new Date(r.paid_date).toLocaleDateString("en-IN",{day:"numeric",month:"short"})}</span>}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}

      {/* Edit Dialog */}
      <Dialog open={showEdit} onOpenChange={o=>!o&&setShowEdit(false)}>
        <DialogContent className="max-w-xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Pencil className="w-5 h-5 text-[#C2185B]"/> Edit Profile — {member.name}
            </DialogTitle>
          </DialogHeader>
          <form onSubmit={handleEdit} className="mt-2">
            <EditMemberForm form={editForm} setForm={setEditForm}/>
            <div className="flex gap-3 justify-end pt-5 mt-2 border-t">
              <Button type="button" variant="outline" onClick={()=>setShowEdit(false)}>Cancel</Button>
              <Button type="submit" className="bg-[#C2185B] hover:bg-[#AD1457] text-white" disabled={editSaving}>
                {editSaving?"Saving...":"Save Changes"}
              </Button>
            </div>
          </form>
        </DialogContent>
      </Dialog>
    </DashboardLayout>
  );
}

// src/pages/Members.tsx
import { useEffect, useState } from "react";
import { DashboardLayout } from "@/components/DashboardLayout";
import { PageHeader } from "@/components/PageHeader";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Link } from "react-router-dom";
import {
  Users, Plus, Search, Phone, MapPin,
  Pencil, Trash2, UserCheck, UserX, ChevronDown, ChevronUp,
} from "lucide-react";
import { membersApi, shgApi } from "@/lib/api";
import { toast } from "sonner";

// ── Constants ─────────────────────────────────────────────────
const ROLES = ["member", "president", "secretary", "treasurer"] as const;
const CASTE_CATEGORIES = ["general", "obc", "sc", "st"] as const;
const ROLE_LABELS: Record<string, string> = {
  member: "Member",
  president: "President",
  secretary: "Secretary",
  treasurer: "Treasurer",
};
const ROLE_COLORS: Record<string, string> = {
  president: "bg-amber-100 text-amber-700",
  secretary: "bg-blue-100 text-blue-700",
  treasurer: "bg-purple-100 text-purple-700",
  member: "bg-gray-100 text-gray-600",
};

const EMPTY_FORM = {
  name: "",
  phone: "",
  age: "",
  income: "",
  aadhar: "",
  husband_name: "",
  occupation: "",
  village: "",
  gram_panchayat: "",
  block: "",
  district: "",
  state: "",
  pin_code: "",
  role: "member" as typeof ROLES[number],
  joined_date: "",
  status: "active" as "active" | "inactive",
  bank_account: "",
  bank_ifsc: "",
  caste_category: "" as typeof CASTE_CATEGORIES[number] | "",
  bpl_status: false,
};

type FormState = typeof EMPTY_FORM;

// ── MemberFormFields — defined OUTSIDE to prevent focus loss ──
function MemberFormFields({
  form,
  setForm,
  shgDefaults,
}: {
  form: FormState;
  setForm: React.Dispatch<React.SetStateAction<FormState>>;
  shgDefaults: { block: string; district: string; state: string };
}) {
  const [showFinancial, setShowFinancial] = useState(false);

  return (
    <div className="space-y-5">
      {/* Personal */}
      <div>
        <p className="text-xs font-semibold text-[#C2185B] uppercase tracking-wider mb-3">
          Personal Details
        </p>
        <div className="grid grid-cols-2 gap-3">
          <div className="col-span-2 space-y-1">
            <Label>Full Name *</Label>
            <Input
              value={form.name}
              onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))}
              placeholder="e.g. Sunita Devi"
              required
            />
          </div>
          <div className="space-y-1">
            <Label>Husband's Name</Label>
            <Input
              value={form.husband_name}
              onChange={(e) => setForm((f) => ({ ...f, husband_name: e.target.value }))}
              placeholder="W/O"
            />
          </div>
          <div className="space-y-1">
            <Label>Phone</Label>
            <Input
              value={form.phone}
              onChange={(e) => setForm((f) => ({ ...f, phone: e.target.value }))}
              placeholder="10-digit number"
              maxLength={10}
            />
          </div>
          <div className="space-y-1">
            <Label>Age</Label>
            <Input
              type="number"
              value={form.age}
              onChange={(e) => setForm((f) => ({ ...f, age: e.target.value }))}
              placeholder="Age"
              min={18}
              max={80}
            />
          </div>
          <div className="space-y-1">
            <Label>Aadhaar Number</Label>
            <Input
              value={form.aadhar}
              onChange={(e) => setForm((f) => ({ ...f, aadhar: e.target.value }))}
              placeholder="12-digit Aadhaar"
              maxLength={12}
            />
          </div>
          <div className="space-y-1">
            <Label>Occupation</Label>
            <Input
              value={form.occupation}
              onChange={(e) => setForm((f) => ({ ...f, occupation: e.target.value }))}
              placeholder="e.g. Dairy, Tailoring"
            />
          </div>
          <div className="space-y-1">
            <Label>Monthly Income (₹)</Label>
            <Input
              type="number"
              value={form.income}
              onChange={(e) => setForm((f) => ({ ...f, income: e.target.value }))}
              placeholder="e.g. 5000"
            />
          </div>
        </div>
      </div>

      {/* Address */}
      <div>
        <p className="text-xs font-semibold text-[#C2185B] uppercase tracking-wider mb-3">
          Address
        </p>
        <div className="grid grid-cols-2 gap-3">
          <div className="space-y-1">
            <Label>Village</Label>
            <Input
              value={form.village}
              onChange={(e) => setForm((f) => ({ ...f, village: e.target.value }))}
              placeholder="Village name"
            />
          </div>
          <div className="space-y-1">
            <Label>Gram Panchayat</Label>
            <Input
              value={form.gram_panchayat}
              onChange={(e) => setForm((f) => ({ ...f, gram_panchayat: e.target.value }))}
              placeholder="GP name"
            />
          </div>
          <div className="space-y-1">
            <Label>Block / Tehsil</Label>
            <Input
              value={form.block}
              onChange={(e) => setForm((f) => ({ ...f, block: e.target.value }))}
              placeholder={shgDefaults.block || "Block"}
            />
          </div>
          <div className="space-y-1">
            <Label>District</Label>
            <Input
              value={form.district}
              onChange={(e) => setForm((f) => ({ ...f, district: e.target.value }))}
              placeholder={shgDefaults.district || "District"}
            />
          </div>
          <div className="space-y-1">
            <Label>State</Label>
            <Input
              value={form.state}
              onChange={(e) => setForm((f) => ({ ...f, state: e.target.value }))}
              placeholder={shgDefaults.state || "State"}
            />
          </div>
          <div className="space-y-1">
            <Label>PIN Code</Label>
            <Input
              value={form.pin_code}
              onChange={(e) => setForm((f) => ({ ...f, pin_code: e.target.value }))}
              placeholder="6-digit PIN"
              maxLength={6}
            />
          </div>
        </div>
      </div>

      {/* Group */}
      <div>
        <p className="text-xs font-semibold text-[#C2185B] uppercase tracking-wider mb-3">
          Group Details
        </p>
        <div className="grid grid-cols-2 gap-3">
          <div className="space-y-1">
            <Label>Role in Group</Label>
            <Select
              value={form.role}
              onValueChange={(v) => setForm((f) => ({ ...f, role: v as typeof ROLES[number] }))}
            >
              <SelectTrigger>
                <SelectValue placeholder="Select role" />
              </SelectTrigger>
              <SelectContent>
                {ROLES.map((r) => (
                  <SelectItem key={r} value={r}>
                    {ROLE_LABELS[r]}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
          <div className="space-y-1">
            <Label>Joining Date</Label>
            <Input
              type="date"
              value={form.joined_date}
              onChange={(e) => setForm((f) => ({ ...f, joined_date: e.target.value }))}
            />
          </div>
        </div>
      </div>

      {/* Financial — collapsible */}
      <div className="border border-dashed border-[#C2185B]/20 rounded-xl overflow-hidden">
        <button
          type="button"
          onClick={() => setShowFinancial((v) => !v)}
          className="w-full flex items-center justify-between px-4 py-3 text-xs font-semibold text-[#C2185B] uppercase tracking-wider hover:bg-[#C2185B]/5 transition-colors"
        >
          Bank & Scheme Details (optional)
          {showFinancial ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
        </button>
        {showFinancial && (
          <div className="px-4 pb-4 grid grid-cols-2 gap-3">
            <div className="space-y-1">
              <Label>Bank Account No.</Label>
              <Input
                value={form.bank_account}
                onChange={(e) => setForm((f) => ({ ...f, bank_account: e.target.value }))}
                placeholder="PMJDY account"
              />
            </div>
            <div className="space-y-1">
              <Label>Bank IFSC</Label>
              <Input
                value={form.bank_ifsc}
                onChange={(e) => setForm((f) => ({ ...f, bank_ifsc: e.target.value }))}
                placeholder="IFSC code"
              />
            </div>
            <div className="space-y-1">
              <Label>Caste Category</Label>
              <Select
                value={form.caste_category}
                onValueChange={(v) =>
                  setForm((f) => ({ ...f, caste_category: v as typeof CASTE_CATEGORIES[number] }))
                }
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select category" />
                </SelectTrigger>
                <SelectContent>
                  {CASTE_CATEGORIES.map((c) => (
                    <SelectItem key={c} value={c}>
                      {c.toUpperCase()}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-1">
              <Label>BPL Status</Label>
              <div className="flex gap-2 mt-1">
                <button
                  type="button"
                  onClick={() => setForm((f) => ({ ...f, bpl_status: true }))}
                  className={`flex-1 py-2 rounded-lg border text-sm font-medium transition-colors ${
                    form.bpl_status
                      ? "bg-orange-50 border-orange-300 text-orange-700"
                      : "border-gray-200 text-gray-500"
                  }`}
                >
                  BPL
                </button>
                <button
                  type="button"
                  onClick={() => setForm((f) => ({ ...f, bpl_status: false }))}
                  className={`flex-1 py-2 rounded-lg border text-sm font-medium transition-colors ${
                    !form.bpl_status
                      ? "bg-gray-50 border-gray-300 text-gray-700"
                      : "border-gray-200 text-gray-500"
                  }`}
                >
                  Non-BPL
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

// ── Main Component ────────────────────────────────────────────
export default function Members() {
  const [members, setMembers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [shgDefaults, setShgDefaults] = useState({ block: "", district: "", state: "" });

  const [showAdd, setShowAdd] = useState(false);
  const [addForm, setAddForm] = useState<FormState>({ ...EMPTY_FORM });
  const [addSaving, setAddSaving] = useState(false);

  const [editMember, setEditMember] = useState<any | null>(null);
  const [editForm, setEditForm] = useState<FormState>({ ...EMPTY_FORM });
  const [editSaving, setEditSaving] = useState(false);

  const [deleteMember, setDeleteMember] = useState<any | null>(null);
  const [deleting, setDeleting] = useState(false);

  useEffect(() => {
    shgApi.get().then((res: any) => {
      const s = res.data;
      const defaults = {
        block: s.block || "",
        district: s.district || "",
        state: s.state || "",
      };
      setShgDefaults(defaults);
      setAddForm((f) => ({ ...f, ...defaults }));
    }).catch(() => {});
    loadMembers();
  }, []);

  async function loadMembers() {
    try {
      const res = await membersApi.list();
      setMembers(res.data);
    } catch {
      toast.error("Failed to load members");
    } finally {
      setLoading(false);
    }
  }

  const filtered = members.filter(
    (m) =>
      m.name.toLowerCase().includes(search.toLowerCase()) ||
      (m.village || "").toLowerCase().includes(search.toLowerCase()) ||
      (m.role || "").toLowerCase().includes(search.toLowerCase())
  );

  async function handleAdd(e: React.FormEvent) {
    e.preventDefault();
    if (!addForm.name.trim()) return toast.error("Name is required");
    setAddSaving(true);
    try {
      await membersApi.create({
        ...addForm,
        age: addForm.age ? Number(addForm.age) : undefined,
        income: addForm.income ? Number(addForm.income) : undefined,
      } as any);
      toast.success(`${addForm.name} added!`);
      setAddForm({ ...EMPTY_FORM, ...shgDefaults });
      setShowAdd(false);
      loadMembers();
    } catch (err: any) {
      toast.error(err.message || "Failed to add member");
    } finally {
      setAddSaving(false);
    }
  }

  function openEdit(m: any) {
    setEditMember(m);
    setEditForm({
      name: m.name || "",
      phone: m.phone || "",
      age: m.age ? String(m.age) : "",
      income: m.income ? String(m.income) : "",
      aadhar: m.aadhar || "",
      husband_name: m.husband_name || "",
      occupation: m.occupation || "",
      village: m.village || "",
      gram_panchayat: m.gram_panchayat || "",
      block: m.block || shgDefaults.block,
      district: m.district || shgDefaults.district,
      state: m.state || shgDefaults.state,
      pin_code: m.pin_code || "",
      role: m.role || "member",
      joined_date: m.joined_date ? m.joined_date.split("T")[0] : "",
      status: m.status || "active",
      bank_account: m.bank_account || "",
      bank_ifsc: m.bank_ifsc || "",
      caste_category: m.caste_category || "",
      bpl_status: m.bpl_status || false,
    });
  }

  async function handleEdit(e: React.FormEvent) {
    e.preventDefault();
    if (!editMember) return;
    setEditSaving(true);
    try {
      await membersApi.update(editMember.id, {
        ...editForm,
        age: editForm.age ? Number(editForm.age) : null,
        income: editForm.income ? Number(editForm.income) : null,
      });
      toast.success("Member updated!");
      setEditMember(null);
      loadMembers();
    } catch (err: any) {
      toast.error(err.message || "Failed to update member");
    } finally {
      setEditSaving(false);
    }
  }

  async function handleDelete() {
    if (!deleteMember) return;
    setDeleting(true);
    try {
      await membersApi.delete(deleteMember.id);
      toast.success(`${deleteMember.name} removed`);
      setDeleteMember(null);
      loadMembers();
    } catch (err: any) {
      toast.error(err.message || "Failed to delete member");
    } finally {
      setDeleting(false);
    }
  }

  return (
    <DashboardLayout>
      <PageHeader
        title="Members"
        description={`${members.length} member${members.length !== 1 ? "s" : ""} in your SHG`}
      />

      <div className="flex items-center gap-3 mb-6">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
          <Input
            className="pl-9"
            placeholder="Search by name, village, or role..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
        <Button
          className="bg-[#C2185B] hover:bg-[#AD1457] text-white shrink-0"
          onClick={() => setShowAdd(true)}
        >
          <Plus className="w-4 h-4 mr-1" /> Add Member
        </Button>
      </div>

      {loading ? (
        <div className="flex justify-center py-16">
          <div className="w-8 h-8 rounded-full border-4 border-[#C2185B]/30 border-t-[#C2185B] animate-spin" />
        </div>
      ) : filtered.length === 0 ? (
        <div className="text-center py-16 text-muted-foreground">
          <Users className="w-12 h-12 mx-auto mb-3 opacity-30" />
          <p className="font-medium">
            {search ? "No members match your search." : "No members yet."}
          </p>
          {!search && <p className="text-sm mt-1">Click "Add Member" to get started.</p>}
        </div>
      ) : (
        <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {filtered.map((member) => (
            <Card
              key={member.id}
              className="hover:border-[#C2185B]/40 hover:shadow-md transition-all border-border group"
            >
              <CardContent className="pt-5">
                <div className="flex items-start gap-3">
                  <Link to={`/members/${member.id}`} className="shrink-0">
                    <div className="w-11 h-11 rounded-full bg-gradient-to-br from-[#C2185B] to-[#6A1B9A] flex items-center justify-center text-white font-bold text-base">
                      {member.name.charAt(0).toUpperCase()}
                    </div>
                  </Link>

                  <Link to={`/members/${member.id}`} className="flex-1 min-w-0">
                    <h3 className="font-semibold truncate hover:text-[#C2185B] transition-colors">
                      {member.name}
                    </h3>
                    {member.husband_name && (
                      <p className="text-xs text-muted-foreground truncate">
                        W/O {member.husband_name}
                      </p>
                    )}
                    {member.village && (
                      <div className="flex items-center gap-1 text-xs text-muted-foreground mt-0.5">
                        <MapPin className="w-3 h-3 shrink-0" />
                        {member.village}{member.block ? `, ${member.block}` : ""}
                      </div>
                    )}
                    {member.phone && (
                      <div className="flex items-center gap-1 text-xs text-muted-foreground mt-0.5">
                        <Phone className="w-3 h-3" />
                        {member.phone}
                      </div>
                    )}
                  </Link>

                  <div className="flex flex-col items-end gap-1.5">
                    <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${ROLE_COLORS[member.role] || ROLE_COLORS.member}`}>
                      {ROLE_LABELS[member.role] || "Member"}
                    </span>
                    <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${member.status === "active" ? "bg-green-100 text-green-700" : "bg-gray-100 text-gray-500"}`}>
                      {member.status === "active" ? "Active" : "Inactive"}
                    </span>
                    <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity mt-0.5">
                      <button
                        onClick={(e) => { e.preventDefault(); openEdit(member); }}
                        className="p-1.5 rounded-lg hover:bg-[#C2185B]/10 text-[#C2185B] transition-colors"
                      >
                        <Pencil className="w-3.5 h-3.5" />
                      </button>
                      <button
                        onClick={(e) => { e.preventDefault(); setDeleteMember(member); }}
                        className="p-1.5 rounded-lg hover:bg-red-50 text-red-500 transition-colors"
                      >
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                    </div>
                  </div>
                </div>

                <div className="flex items-center gap-3 mt-3 pt-3 border-t border-border/50 pl-14 flex-wrap">
                  {member.occupation && (
                    <span className="text-xs text-muted-foreground">{member.occupation}</span>
                  )}
                  {member.caste_category && (
                    <span className="text-xs uppercase bg-gray-50 px-1.5 py-0.5 rounded text-gray-500">
                      {member.caste_category}
                    </span>
                  )}
                  {member.bpl_status && (
                    <span className="text-xs bg-orange-50 text-orange-600 px-1.5 py-0.5 rounded">BPL</span>
                  )}
                  {member.joined_date && (
                    <span className="text-xs text-muted-foreground ml-auto">
                      {new Date(member.joined_date).toLocaleDateString("en-IN", { month: "short", year: "numeric" })}
                    </span>
                  )}
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Add Dialog */}
      <Dialog open={showAdd} onOpenChange={setShowAdd}>
        <DialogContent className="max-w-xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <UserCheck className="w-5 h-5 text-[#C2185B]" /> Add New Member
            </DialogTitle>
          </DialogHeader>
          <form onSubmit={handleAdd} className="mt-2">
            <MemberFormFields form={addForm} setForm={setAddForm} shgDefaults={shgDefaults} />
            <div className="flex gap-3 justify-end pt-4">
              <Button type="button" variant="outline" onClick={() => setShowAdd(false)}>Cancel</Button>
              <Button type="submit" className="bg-[#C2185B] hover:bg-[#AD1457] text-white" disabled={addSaving}>
                {addSaving ? "Adding..." : "Add Member"}
              </Button>
            </div>
          </form>
        </DialogContent>
      </Dialog>

      {/* Edit Dialog */}
      <Dialog open={!!editMember} onOpenChange={(o) => !o && setEditMember(null)}>
        <DialogContent className="max-w-xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Pencil className="w-5 h-5 text-[#C2185B]" /> Edit — {editMember?.name}
            </DialogTitle>
          </DialogHeader>
          <form onSubmit={handleEdit} className="mt-2">
            <MemberFormFields form={editForm} setForm={setEditForm} shgDefaults={shgDefaults} />
            <div className="space-y-1 pt-4">
              <Label>Member Status</Label>
              <div className="flex gap-3 mt-1">
                <button type="button" onClick={() => setEditForm((f) => ({ ...f, status: "active" }))}
                  className={`flex items-center gap-1.5 px-3 py-2 rounded-lg border text-sm font-medium transition-colors ${editForm.status === "active" ? "bg-green-50 border-green-300 text-green-700" : "border-gray-200 text-gray-500"}`}>
                  <UserCheck className="w-3.5 h-3.5" /> Active
                </button>
                <button type="button" onClick={() => setEditForm((f) => ({ ...f, status: "inactive" }))}
                  className={`flex items-center gap-1.5 px-3 py-2 rounded-lg border text-sm font-medium transition-colors ${editForm.status === "inactive" ? "bg-red-50 border-red-300 text-red-600" : "border-gray-200 text-gray-500"}`}>
                  <UserX className="w-3.5 h-3.5" /> Inactive
                </button>
              </div>
            </div>
            <div className="flex gap-3 justify-end pt-4">
              <Button type="button" variant="outline" onClick={() => setEditMember(null)}>Cancel</Button>
              <Button type="submit" className="bg-[#C2185B] hover:bg-[#AD1457] text-white" disabled={editSaving}>
                {editSaving ? "Saving..." : "Save Changes"}
              </Button>
            </div>
          </form>
        </DialogContent>
      </Dialog>

      {/* Delete Confirm */}
      <AlertDialog open={!!deleteMember} onOpenChange={(o) => !o && setDeleteMember(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Remove {deleteMember?.name}?</AlertDialogTitle>
            <AlertDialogDescription>
              This will permanently delete this member and all their savings, loan,
              and repayment records. This cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={deleting}>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={handleDelete} disabled={deleting} className="bg-red-600 hover:bg-red-700 text-white">
              {deleting ? "Deleting..." : "Yes, Remove"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </DashboardLayout>
  );
}

// src/pages/Repayments.tsx
import { useEffect, useState } from "react";
import { DashboardLayout } from "@/components/DashboardLayout";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import {
  Table, TableBody, TableCell, TableHead, TableHeader, TableRow,
} from "@/components/ui/table";
import {
  CheckCircle2, AlertCircle, Clock, IndianRupee,
  CalendarCheck, TrendingUp, AlertTriangle, BadgeCheck,
} from "lucide-react";
import { repaymentsApi } from "@/lib/api";
import { toast } from "sonner";
import { Link } from "react-router-dom";

type Tab = "pending" | "overdue" | "history";

export default function Repayments() {
  const [allRepayments, setAllRepayments] = useState<any[]>([]);
  const [loading, setLoading]             = useState(true);
  const [tab, setTab]                     = useState<Tab>("pending");

  // Pay confirm dialog
  const [payTarget, setPayTarget]   = useState<any | null>(null);
  const [paying, setPaying]         = useState(false);
  const [payDate, setPayDate]       = useState(new Date().toISOString().split("T")[0]);

  useEffect(() => { loadAll(); }, []);

  async function loadAll() {
    setLoading(true);
    try {
      const res = await repaymentsApi.list();
      setAllRepayments(res.data || []);
    } catch (err: any) {
      toast.error(err.message || "Failed to load repayments");
    } finally {
      setLoading(false);
    }
  }

  async function handlePay() {
    if (!payTarget) return;
    setPaying(true);
    try {
      await repaymentsApi.pay(payTarget.id, payDate);
      toast.success(`EMI marked as paid for ${payTarget.member_name}`);
      setPayTarget(null);
      loadAll();
    } catch (err: any) {
      toast.error(err.message || "Failed to mark payment");
    } finally {
      setPaying(false);
    }
  }

  // ── Derived data ──────────────────────────────────────────
  const pending  = allRepayments.filter(r => r.status === "pending");
  const overdue  = allRepayments.filter(r => r.status === "overdue");
  const paid     = allRepayments.filter(r => r.status === "paid");

  const totalCollected  = paid.reduce((s, r) => s + Number(r.emi_amount), 0);
  const totalPending    = pending.reduce((s, r) => s + Number(r.emi_amount), 0);
  const totalOverdue    = overdue.reduce((s, r) => s + Number(r.emi_amount), 0);

  // Due this month
  const now = new Date();
  const dueThisMonth = allRepayments.filter(r => {
    const d = new Date(r.due_date);
    return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear()
      && r.status !== "paid";
  });

  const displayList = tab === "pending" ? pending : tab === "overdue" ? overdue : paid;

  // ── Row component ─────────────────────────────────────────
  function RepRow({ r }: { r: any }) {
    const isActionable = r.status === "pending" || r.status === "overdue";
    return (
      <TableRow className={`hover:bg-gray-50/50 ${r.status === "overdue" ? "bg-red-50/30" : ""}`}>
        <TableCell>
          <Link to={`/members/${r.member_id}`}
            className="font-medium text-gray-900 hover:text-[#C2185B] transition-colors">
            {r.member_name}
          </Link>
        </TableCell>
        <TableCell className="text-muted-foreground text-sm">
          {new Date(r.due_date).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" })}
        </TableCell>
        <TableCell>
          <span className="font-semibold text-gray-900">
            ₹{Number(r.emi_amount).toLocaleString("en-IN")}
          </span>
        </TableCell>
        <TableCell>
          <span className={`inline-flex items-center gap-1 text-xs px-2.5 py-1 rounded-full font-medium ${
            r.status === "paid"    ? "bg-green-100 text-green-700" :
            r.status === "overdue" ? "bg-red-100 text-red-600" :
            "bg-amber-100 text-amber-700"
          }`}>
            {r.status === "paid"    && <CheckCircle2 className="w-3 h-3" />}
            {r.status === "overdue" && <AlertCircle  className="w-3 h-3" />}
            {r.status === "pending" && <Clock        className="w-3 h-3" />}
            {r.status.charAt(0).toUpperCase() + r.status.slice(1)}
          </span>
        </TableCell>
        <TableCell className="text-muted-foreground text-sm">
          {r.paid_date
            ? new Date(r.paid_date).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" })
            : "—"}
        </TableCell>
        <TableCell>
          {isActionable && (
            <Button
              size="sm"
              onClick={() => { setPayTarget(r); setPayDate(new Date().toISOString().split("T")[0]); }}
              className="bg-[#C2185B] hover:bg-[#AD1457] text-white h-7 text-xs px-3"
            >
              Mark Paid
            </Button>
          )}
        </TableCell>
      </TableRow>
    );
  }

  if (loading) return (
    <DashboardLayout>
      <div className="flex justify-center py-24">
        <div className="w-8 h-8 rounded-full border-4 border-[#C2185B]/30 border-t-[#C2185B] animate-spin" />
      </div>
    </DashboardLayout>
  );

  return (
    <DashboardLayout>
      {/* Header */}
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-gray-900">Repayments</h1>
        <p className="text-sm text-muted-foreground mt-0.5">Track EMI collections across all active loans</p>
      </div>

      {/* Stat cards */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
        {[
          { icon: BadgeCheck,    color: "#388E3C", label: "Total Collected",  value: `₹${totalCollected.toLocaleString("en-IN")}`,  sub: `${paid.length} EMIs paid` },
          { icon: Clock,         color: "#F57C00", label: "Pending",          value: `₹${totalPending.toLocaleString("en-IN")}`,    sub: `${pending.length} EMIs due` },
          { icon: AlertTriangle, color: "#D32F2F", label: "Overdue",          value: `₹${totalOverdue.toLocaleString("en-IN")}`,   sub: `${overdue.length} EMIs overdue` },
          { icon: CalendarCheck, color: "#6A1B9A", label: "Due This Month",   value: dueThisMonth.length,                           sub: `EMIs to collect` },
        ].map(({ icon: Icon, color, label, value, sub }) => (
          <Card key={label} className={`border-border/60 shadow-sm ${label === "Overdue" && overdue.length > 0 ? "border-red-200" : ""}`}>
            <CardContent className="pt-4 pb-4">
              <div className="flex items-start gap-3">
                <div className="w-9 h-9 rounded-xl flex items-center justify-center shrink-0"
                  style={{ backgroundColor: `${color}15` }}>
                  <Icon className="w-4 h-4" style={{ color }} />
                </div>
                <div>
                  <p className="text-xs text-muted-foreground">{label}</p>
                  <p className="text-xl font-bold text-gray-900 leading-tight">{value}</p>
                  <p className="text-xs text-muted-foreground">{sub}</p>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Overdue alert banner */}
      {overdue.length > 0 && (
        <div className="flex items-start gap-3 bg-red-50 border border-red-200 rounded-xl px-4 py-3 mb-6">
          <AlertCircle className="w-5 h-5 text-red-500 shrink-0 mt-0.5" />
          <div>
            <p className="text-sm font-semibold text-red-700">
              {overdue.length} overdue EMI{overdue.length > 1 ? "s" : ""} need immediate attention
            </p>
            <p className="text-xs text-red-600 mt-0.5">
              Total overdue: ₹{totalOverdue.toLocaleString("en-IN")} · 
              Members: {[...new Set(overdue.map(r => r.member_name))].join(", ")}
            </p>
          </div>
        </div>
      )}

      {/* Tabs */}
      <div className="flex gap-1 bg-gray-100 rounded-xl p-1 mb-6 w-fit">
        {([
          { key: "pending",  label: `Pending (${pending.length})` },
          { key: "overdue",  label: `Overdue (${overdue.length})` },
          { key: "history",  label: `History (${paid.length})` },
        ] as const).map(t => (
          <button key={t.key} onClick={() => setTab(t.key)}
            className={`px-5 py-2 rounded-lg text-sm font-medium transition-all ${
              tab === t.key ? "bg-white shadow text-[#C2185B]" : "text-muted-foreground hover:text-foreground"
            } ${t.key === "overdue" && overdue.length > 0 ? "text-red-500" : ""}`}>
            {t.label}
          </button>
        ))}
      </div>

      {/* Table */}
      <Card className="border-border/60">
        <CardContent className="pt-0">
          {displayList.length === 0 ? (
            <div className="py-20 text-center text-muted-foreground">
              {tab === "pending"  && <><Clock className="w-10 h-10 mx-auto mb-2 opacity-20" /><p>No pending EMIs</p></>}
              {tab === "overdue"  && <><AlertCircle className="w-10 h-10 mx-auto mb-2 opacity-20 text-green-500" /><p className="text-green-600 font-medium">No overdue EMIs — great!</p></>}
              {tab === "history"  && <><CheckCircle2 className="w-10 h-10 mx-auto mb-2 opacity-20" /><p>No payments recorded yet</p></>}
            </div>
          ) : (
            <>
              <div className="overflow-x-auto">
                <Table>
                  <TableHeader>
                    <TableRow className="bg-gray-50">
                      <TableHead>Member</TableHead>
                      <TableHead>Due Date</TableHead>
                      <TableHead>EMI Amount</TableHead>
                      <TableHead>Status</TableHead>
                      <TableHead>Paid On</TableHead>
                      <TableHead></TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {displayList.map(r => <RepRow key={r.id} r={r} />)}
                  </TableBody>
                </Table>
              </div>

              {/* Footer totals */}
              <div className="mt-4 p-3 bg-gray-50 rounded-xl flex justify-between items-center">
                <span className="text-sm text-muted-foreground">
                  {displayList.length} {tab === "history" ? "payments" : "EMIs"}
                </span>
                <span className="text-base font-bold text-[#C2185B]">
                  ₹{displayList.reduce((s, r) => s + Number(r.emi_amount), 0).toLocaleString("en-IN")}
                </span>
              </div>
            </>
          )}
        </CardContent>
      </Card>

      {/* Mark Paid Dialog */}
      <Dialog open={!!payTarget} onOpenChange={o => !o && setPayTarget(null)}>
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <CheckCircle2 className="w-5 h-5 text-green-600" />
              Mark EMI as Paid
            </DialogTitle>
          </DialogHeader>
          {payTarget && (
            <div className="space-y-4 py-1">
              {/* Summary */}
              <div className="rounded-xl bg-gray-50 p-4 space-y-2 text-sm">
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Member</span>
                  <span className="font-medium">{payTarget.member_name}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Due Date</span>
                  <span className="font-medium">
                    {new Date(payTarget.due_date).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" })}
                  </span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Amount</span>
                  <span className="font-bold text-[#C2185B]">₹{Number(payTarget.emi_amount).toLocaleString("en-IN")}</span>
                </div>
              </div>

              {/* Payment date */}
              <div className="space-y-1">
                <label className="text-sm font-medium text-gray-700">Payment Date</label>
                <input
                  type="date"
                  value={payDate}
                  onChange={e => setPayDate(e.target.value)}
                  className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:border-[#C2185B]"
                />
              </div>

              <div className="flex gap-3 pt-1">
                <Button variant="outline" className="flex-1" onClick={() => setPayTarget(null)}>
                  Cancel
                </Button>
                <Button
                  className="flex-1 bg-green-600 hover:bg-green-700 text-white"
                  onClick={handlePay} disabled={paying}
                >
                  {paying ? "Saving..." : "Confirm Payment"}
                </Button>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </DashboardLayout>
  );
}

// src/pages/Reports.tsx
import { useEffect, useState } from "react";
import { DashboardLayout } from "@/components/DashboardLayout";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer,
  LineChart, Line, PieChart, Pie, Cell, CartesianGrid, Legend,
} from "recharts";
import {
  Users, PiggyBank, Landmark, CalendarCheck,
  TrendingUp, BadgeCheck, AlertCircle, Activity,
} from "lucide-react";
import { dashboardApi, savingsApi, loansApi, repaymentsApi, membersApi } from "@/lib/api";
import { toast } from "sonner";

const MONTHS = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
const COLORS  = ["#C2185B","#6A1B9A","#0288D1","#F57C00","#388E3C","#00897B","#AD1457","#7B1FA2"];

// ── Custom tooltip ────────────────────────────────────────────
function ChartTooltip({ active, payload, label, prefix = "₹" }: any) {
  if (!active || !payload?.length) return null;
  return (
    <div className="bg-white border border-gray-100 shadow-lg rounded-xl px-3 py-2 text-sm">
      <p className="font-semibold text-gray-700 mb-1">{label}</p>
      {payload.map((p: any, i: number) => (
        <p key={i} style={{ color: p.color }}>
          {p.name}: {prefix}{Number(p.value).toLocaleString("en-IN")}
        </p>
      ))}
    </div>
  );
}

export default function Reports() {
  const [stats, setStats]         = useState<any>(null);
  const [savings, setSavings]     = useState<any[]>([]);
  const [loans, setLoans]         = useState<any[]>([]);
  const [repayments, setRepayments] = useState<any[]>([]);
  const [members, setMembers]     = useState<any[]>([]);
  const [loading, setLoading]     = useState(true);

  useEffect(() => { loadAll(); }, []);

  async function loadAll() {
    try {
      const [dashRes, savRes, loanRes, repRes, memRes] = await Promise.all([
        dashboardApi.get(),
        savingsApi.list(),
        loansApi.list(),
        repaymentsApi.list(),
        membersApi.list(),
      ]);
      setStats(dashRes.data);
      setSavings(savRes.data || []);
      setLoans(loanRes.data || []);
      setRepayments(repRes.data || []);
      setMembers(memRes.data || []);
    } catch (err: any) {
      toast.error("Failed to load reports");
    } finally {
      setLoading(false);
    }
  }

  // ── Derived chart data ────────────────────────────────────

  // Monthly savings trend (last 14 months)
  const savingsByMonth: Record<string, number> = {};
  savings.forEach(s => {
    const key = `${MONTHS[s.month - 1]} ${String(s.year).slice(2)}`;
    savingsByMonth[key] = (savingsByMonth[key] || 0) + Number(s.amount);
  });
  const savingsTrend = Object.entries(savingsByMonth)
    .sort((a, b) => {
      const [am, ay] = a[0].split(" ");
      const [bm, by] = b[0].split(" ");
      return (Number(ay) * 12 + MONTHS.indexOf(am)) - (Number(by) * 12 + MONTHS.indexOf(bm));
    })
    .slice(-12)
    .map(([month, amount]) => ({ month, amount }));

  // Loan disbursals by month
  const loansByMonth: Record<string, number> = {};
  loans.forEach(l => {
    if (!l.disbursed_date) return;
    const d = new Date(l.disbursed_date);
    const key = `${MONTHS[d.getMonth()]} ${String(d.getFullYear()).slice(2)}`;
    loansByMonth[key] = (loansByMonth[key] || 0) + Number(l.loan_amount);
  });
  const loansTrend = Object.entries(loansByMonth)
    .sort((a, b) => {
      const [am, ay] = a[0].split(" ");
      const [bm, by] = b[0].split(" ");
      return (Number(ay) * 12 + MONTHS.indexOf(am)) - (Number(by) * 12 + MONTHS.indexOf(bm));
    })
    .slice(-12)
    .map(([month, amount]) => ({ month, amount }));

  // Loan purpose breakdown (pie)
  const purposeMap: Record<string, number> = {};
  loans.forEach(l => {
    const p = l.purpose || "Other";
    purposeMap[p] = (purposeMap[p] || 0) + 1;
  });
  const purposePie = Object.entries(purposeMap)
    .sort((a, b) => b[1] - a[1])
    .map(([name, value]) => ({ name, value }));

  // Repayment status breakdown (pie)
  const statusMap = { paid: 0, pending: 0, overdue: 0 };
  repayments.forEach(r => { statusMap[r.status as keyof typeof statusMap]++; });
  const repaymentPie = [
    { name: "Paid",    value: statusMap.paid,    color: "#388E3C" },
    { name: "Pending", value: statusMap.pending, color: "#F57C00" },
    { name: "Overdue", value: statusMap.overdue, color: "#D32F2F" },
  ].filter(d => d.value > 0);

  // Loan status breakdown
  const loanStatusMap = { active: 0, closed: 0, overdue: 0 };
  loans.forEach(l => { loanStatusMap[l.status as keyof typeof loanStatusMap]++; });

  // Member savings leaderboard (top 8)
  const memberSavingsMap: Record<string, { name: string; total: number }> = {};
  savings.forEach(s => {
    if (!memberSavingsMap[s.member_id]) {
      memberSavingsMap[s.member_id] = { name: s.member_name || "Member", total: 0 };
    }
    memberSavingsMap[s.member_id].total += Number(s.amount);
  });
  const leaderboard = Object.values(memberSavingsMap)
    .sort((a, b) => b.total - a.total)
    .slice(0, 8)
    .map(m => ({ name: m.name.split(" ")[0], total: m.total }));

  // Caste distribution
  const casteMap: Record<string, number> = {};
  members.forEach(m => { casteMap[m.caste_category || "unknown"]++; });
  const castePie = Object.entries(casteMap).map(([name, value]) => ({ name: name.toUpperCase(), value }));

  // Collection rate per month
  const collectionRate = savingsTrend.map(s => ({
    month: s.month,
    rate: members.length > 0 ? Math.min(100, Math.round((s.amount / (members.length * 500)) * 100)) : 0,
  }));

  if (loading) return (
    <DashboardLayout>
      <div className="flex justify-center py-24">
        <div className="w-8 h-8 rounded-full border-4 border-[#C2185B]/30 border-t-[#C2185B] animate-spin" />
      </div>
    </DashboardLayout>
  );

  return (
    <DashboardLayout>
      {/* Header */}
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-gray-900">Reports & Insights</h1>
        <p className="text-sm text-muted-foreground mt-0.5">Financial analytics and trends for your SHG</p>
      </div>

      {/* ── Summary stat cards ─────────────────────────────── */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-7">
        {[
          { icon: Users,       color: "#C2185B", label: "Total Members",        value: stats?.totalMembers ?? 0,                                                           sub: `${stats?.activeMembers ?? 0} active` },
          { icon: PiggyBank,   color: "#6A1B9A", label: "Total Savings",        value: `₹${Number(stats?.totalSavings ?? 0).toLocaleString("en-IN")}`,                    sub: `Avg ₹${Number(stats?.averageSavingsPerMember ?? 0).toLocaleString("en-IN")}/member` },
          { icon: Landmark,    color: "#0288D1", label: "Loans Disbursed",      value: `₹${Number(stats?.totalLoansDisbursed ?? 0).toLocaleString("en-IN")}`,             sub: `${loans.length} total loans` },
          { icon: BadgeCheck,  color: "#388E3C", label: "Repayments Collected", value: `₹${Number(stats?.totalRepaymentsCollected ?? 0).toLocaleString("en-IN")}`,        sub: `${statusMap.paid} EMIs paid` },
        ].map(({ icon: Icon, color, label, value, sub }) => (
          <Card key={label} className="border-border/50 shadow-sm">
            <CardContent className="pt-4 pb-4">
              <div className="flex items-start gap-3">
                <div className="w-9 h-9 rounded-xl flex items-center justify-center shrink-0" style={{ backgroundColor: `${color}15` }}>
                  <Icon className="w-4 h-4" style={{ color }} />
                </div>
                <div>
                  <p className="text-xs text-muted-foreground">{label}</p>
                  <p className="text-xl font-bold text-gray-900 leading-tight">{value}</p>
                  <p className="text-xs font-medium mt-0.5" style={{ color }}>{sub}</p>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* ── Row 1: Savings trend + Loan disbursals ─────────── */}
      <div className="grid md:grid-cols-2 gap-5 mb-5">

        {/* Savings trend */}
        <Card className="border-border/50 shadow-sm">
          <CardHeader className="px-5 pt-5 pb-3">
            <CardTitle className="text-sm font-semibold text-gray-700 flex items-center gap-2">
              <PiggyBank className="w-4 h-4 text-[#6A1B9A]" /> Monthly Savings Trend
            </CardTitle>
          </CardHeader>
          <CardContent className="px-5 pb-5">
            {savingsTrend.length === 0 ? (
              <p className="text-center text-muted-foreground py-10 text-sm">No data yet</p>
            ) : (
              <ResponsiveContainer width="100%" height={220}>
                <BarChart data={savingsTrend} barSize={24}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" vertical={false} />
                  <XAxis dataKey="month" tick={{ fontSize: 11, fill: "#9ca3af" }} axisLine={false} tickLine={false} />
                  <YAxis tick={{ fontSize: 11, fill: "#9ca3af" }} axisLine={false} tickLine={false}
                    tickFormatter={v => `₹${v >= 1000 ? `${(v/1000).toFixed(0)}k` : v}`} />
                  <Tooltip content={<ChartTooltip />} />
                  <Bar dataKey="amount" name="Savings" fill="#6A1B9A" radius={[6,6,0,0]}
                    background={{ fill: "#f9f9f9", radius: 6 }} />
                </BarChart>
              </ResponsiveContainer>
            )}
          </CardContent>
        </Card>

        {/* Loan disbursals */}
        <Card className="border-border/50 shadow-sm">
          <CardHeader className="px-5 pt-5 pb-3">
            <CardTitle className="text-sm font-semibold text-gray-700 flex items-center gap-2">
              <Landmark className="w-4 h-4 text-[#0288D1]" /> Loan Disbursals by Month
            </CardTitle>
          </CardHeader>
          <CardContent className="px-5 pb-5">
            {loansTrend.length === 0 ? (
              <p className="text-center text-muted-foreground py-10 text-sm">No loans yet</p>
            ) : (
              <ResponsiveContainer width="100%" height={220}>
                <BarChart data={loansTrend} barSize={24}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" vertical={false} />
                  <XAxis dataKey="month" tick={{ fontSize: 11, fill: "#9ca3af" }} axisLine={false} tickLine={false} />
                  <YAxis tick={{ fontSize: 11, fill: "#9ca3af" }} axisLine={false} tickLine={false}
                    tickFormatter={v => `₹${v >= 1000 ? `${(v/1000).toFixed(0)}k` : v}`} />
                  <Tooltip content={<ChartTooltip />} />
                  <Bar dataKey="amount" name="Disbursed" fill="#0288D1" radius={[6,6,0,0]}
                    background={{ fill: "#f9f9f9", radius: 6 }} />
                </BarChart>
              </ResponsiveContainer>
            )}
          </CardContent>
        </Card>
      </div>

      {/* ── Row 2: Collection rate line + Member leaderboard ── */}
      <div className="grid md:grid-cols-2 gap-5 mb-5">

        {/* Collection rate */}
        <Card className="border-border/50 shadow-sm">
          <CardHeader className="px-5 pt-5 pb-3">
            <CardTitle className="text-sm font-semibold text-gray-700 flex items-center gap-2">
              <Activity className="w-4 h-4 text-[#C2185B]" /> Monthly Collection Rate (%)
            </CardTitle>
          </CardHeader>
          <CardContent className="px-5 pb-5">
            {collectionRate.length === 0 ? (
              <p className="text-center text-muted-foreground py-10 text-sm">No data yet</p>
            ) : (
              <ResponsiveContainer width="100%" height={220}>
                <LineChart data={collectionRate}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" vertical={false} />
                  <XAxis dataKey="month" tick={{ fontSize: 11, fill: "#9ca3af" }} axisLine={false} tickLine={false} />
                  <YAxis domain={[0, 100]} tick={{ fontSize: 11, fill: "#9ca3af" }} axisLine={false} tickLine={false}
                    tickFormatter={v => `${v}%`} />
                  <Tooltip content={<ChartTooltip prefix="" />} />
                  <Line type="monotone" dataKey="rate" name="Collection %" stroke="#C2185B"
                    strokeWidth={2.5} dot={{ fill: "#C2185B", r: 4 }} activeDot={{ r: 6 }} />
