        </Card>

        {/* Loan purpose pie */}
        <Card className="border-border/50 shadow-sm">
          <CardHeader className="px-5 pt-5 pb-3">
            <CardTitle className="text-sm font-semibold text-gray-700 flex items-center gap-2">
              <Landmark className="w-4 h-4 text-[#0288D1]" /> Loan Purposes
            </CardTitle>
          </CardHeader>
          <CardContent className="px-5 pb-5">
            {purposePie.length === 0 ? (
              <p className="text-center text-muted-foreground py-10 text-sm">No loans yet</p>
            ) : (
              <>
                <ResponsiveContainer width="100%" height={160}>
                  <PieChart>
                    <Pie data={purposePie} cx="50%" cy="50%" innerRadius={45} outerRadius={70}
                      paddingAngle={3} dataKey="value">
                      {purposePie.map((_, i) => (
                        <Cell key={i} fill={COLORS[i % COLORS.length]} />
                      ))}
                    </Pie>
                    <Tooltip formatter={(v: any, n: any) => [`${v} loans`, n]} />
                  </PieChart>
                </ResponsiveContainer>
                <div className="space-y-1.5 mt-2">
                  {purposePie.slice(0, 4).map((d, i) => (
                    <div key={d.name} className="flex items-center justify-between text-xs">
                      <div className="flex items-center gap-1.5">
                        <div className="w-2 h-2 rounded-full" style={{ backgroundColor: COLORS[i % COLORS.length] }} />
                        <span className="text-gray-600 truncate max-w-[120px]">{d.name}</span>
                      </div>
                      <span className="font-semibold">{d.value}</span>
                    </div>
                  ))}
                </div>
              </>
            )}
          </CardContent>
        </Card>

        {/* Caste distribution */}
        <Card className="border-border/50 shadow-sm">
          <CardHeader className="px-5 pt-5 pb-3">
            <CardTitle className="text-sm font-semibold text-gray-700 flex items-center gap-2">
              <Users className="w-4 h-4 text-[#C2185B]" /> Member Categories
            </CardTitle>
          </CardHeader>
          <CardContent className="px-5 pb-5">
            {castePie.length === 0 ? (
              <p className="text-center text-muted-foreground py-10 text-sm">No data</p>
            ) : (
              <>
                <ResponsiveContainer width="100%" height={160}>
                  <PieChart>
                    <Pie data={castePie} cx="50%" cy="50%" innerRadius={45} outerRadius={70}
                      paddingAngle={3} dataKey="value">
                      {castePie.map((_, i) => (
                        <Cell key={i} fill={COLORS[i % COLORS.length]} />
                      ))}
                    </Pie>
                    <Tooltip formatter={(v: any, n: any) => [`${v} members`, n]} />
                  </PieChart>
                </ResponsiveContainer>
                <div className="space-y-1.5 mt-2">
                  {castePie.map((d, i) => (
                    <div key={d.name} className="flex items-center justify-between text-xs">
                      <div className="flex items-center gap-1.5">
                        <div className="w-2 h-2 rounded-full" style={{ backgroundColor: COLORS[i % COLORS.length] }} />
                        <span className="text-gray-600">{d.name}</span>
                      </div>
                      <span className="font-semibold">{d.value}</span>
                    </div>
                  ))}
                </div>
              </>
            )}
          </CardContent>
        </Card>
      </div>

      {/* ── Row 4: Loan portfolio summary ─────────────────── */}
      <Card className="border-border/50 shadow-sm">
        <CardHeader className="px-5 pt-5 pb-3">
          <CardTitle className="text-sm font-semibold text-gray-700 flex items-center gap-2">
            <Activity className="w-4 h-4 text-[#6A1B9A]" /> Loan Portfolio Summary
          </CardTitle>
        </CardHeader>
        <CardContent className="px-5 pb-5">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-5">
            {[
              { label: "Total Loans",       value: loans.length,                                                                  color: "#6A1B9A" },
              { label: "Active",            value: loanStatusMap.active,                                                          color: "#0288D1" },
              { label: "Closed",            value: loanStatusMap.closed,                                                          color: "#388E3C" },
              { label: "Overdue",           value: loanStatusMap.overdue,                                                         color: "#D32F2F" },
            ].map(({ label, value, color }) => (
              <div key={label} className="text-center p-3 rounded-xl bg-gray-50">
                <p className="text-2xl font-bold" style={{ color }}>{value}</p>
                <p className="text-xs text-muted-foreground mt-0.5">{label}</p>
              </div>
            ))}
          </div>

          {/* Per-member loan table */}
          {loans.length > 0 && (
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead>
                  <tr className="border-b text-left">
                    <th className="pb-2 text-xs text-muted-foreground font-medium">Member</th>
                    <th className="pb-2 text-xs text-muted-foreground font-medium text-right">Amount</th>
                    <th className="pb-2 text-xs text-muted-foreground font-medium">Purpose</th>
                    <th className="pb-2 text-xs text-muted-foreground font-medium">Status</th>
                    <th className="pb-2 text-xs text-muted-foreground font-medium">Disbursed</th>
                  </tr>
                </thead>
                <tbody>
                  {loans.map(l => (
                    <tr key={l.id} className="border-b last:border-0 hover:bg-gray-50/50">
                      <td className="py-2 font-medium text-gray-900">{l.member_name}</td>
                      <td className="py-2 text-right font-semibold">₹{Number(l.loan_amount).toLocaleString("en-IN")}</td>
                      <td className="py-2 text-muted-foreground truncate max-w-[120px]">{l.purpose || "—"}</td>
                      <td className="py-2">
                        <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${
                          l.status === "closed"  ? "bg-green-100 text-green-700" :
                          l.status === "overdue" ? "bg-red-100 text-red-600" :
                          "bg-blue-100 text-blue-700"}`}>
                          {l.status}
                        </span>
                      </td>
                      <td className="py-2 text-muted-foreground text-xs">
                        {l.disbursed_date ? new Date(l.disbursed_date).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "2-digit" }) : "—"}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </CardContent>
      </Card>

    </DashboardLayout>
  );
}

// src/pages/Savings.tsx
import { useEffect, useState, useCallback } from "react";
import { DashboardLayout } from "@/components/DashboardLayout";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import {
  Table, TableBody, TableCell, TableHead, TableHeader, TableRow,
} from "@/components/ui/table";
import {
  Plus, PiggyBank, TrendingUp, Calendar, Trash2, AlertCircle,
  ChevronLeft, ChevronRight, Users, CheckCircle2,
} from "lucide-react";
import { savingsApi, membersApi } from "@/lib/api";
import { toast } from "sonner";
import { Link } from "react-router-dom";

// ── Constants ─────────────────────────────────────────────────
const MONTH_NAMES = [
  "January","February","March","April","May","June",
  "July","August","September","October","November","December",
];
const PAYMENT_MODES = ["cash", "upi", "bank"];
const CURRENT_YEAR  = new Date().getFullYear();
const CURRENT_MONTH = new Date().getMonth() + 1;
const YEARS = Array.from({ length: 5 }, (_, i) => CURRENT_YEAR - i);

// ── Add Saving Form — outside to avoid focus loss ─────────────
const EMPTY_FORM = {
  member_id: "", month: String(CURRENT_MONTH), year: String(CURRENT_YEAR),
  amount: "", payment_mode: "cash", date: new Date().toISOString().split("T")[0],
};
type SavingForm = typeof EMPTY_FORM;

function AddSavingForm({
  members, form, setForm,
}: {
  members: any[];
  form: SavingForm;
  setForm: React.Dispatch<React.SetStateAction<SavingForm>>;
}) {
  return (
    <div className="space-y-4">
      <div className="space-y-1">
        <Label>Member *</Label>
        <Select value={form.member_id} onValueChange={v => setForm(f => ({ ...f, member_id: v }))}>
          <SelectTrigger><SelectValue placeholder="Select member" /></SelectTrigger>
          <SelectContent>
            {members.map(m => (
              <SelectItem key={m.id} value={m.id}>{m.name}</SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>
      <div className="grid grid-cols-2 gap-3">
        <div className="space-y-1">
          <Label>Month *</Label>
          <Select value={form.month} onValueChange={v => setForm(f => ({ ...f, month: v }))}>
            <SelectTrigger><SelectValue /></SelectTrigger>
            <SelectContent>
              {MONTH_NAMES.map((m, i) => (
                <SelectItem key={i + 1} value={String(i + 1)}>{m}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
        <div className="space-y-1">
          <Label>Year *</Label>
          <Select value={form.year} onValueChange={v => setForm(f => ({ ...f, year: v }))}>
            <SelectTrigger><SelectValue /></SelectTrigger>
            <SelectContent>
              {YEARS.map(y => <SelectItem key={y} value={String(y)}>{y}</SelectItem>)}
            </SelectContent>
          </Select>
        </div>
      </div>
      <div className="grid grid-cols-2 gap-3">
        <div className="space-y-1">
          <Label>Amount (₹) *</Label>
          <Input
            type="number" placeholder="e.g. 500"
            value={form.amount} onChange={e => setForm(f => ({ ...f, amount: e.target.value }))}
          />
        </div>
        <div className="space-y-1">
          <Label>Payment Mode</Label>
          <Select value={form.payment_mode} onValueChange={v => setForm(f => ({ ...f, payment_mode: v }))}>
            <SelectTrigger><SelectValue /></SelectTrigger>
            <SelectContent>
              {PAYMENT_MODES.map(m => (
                <SelectItem key={m} value={m}>{m.toUpperCase()}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>
      <div className="space-y-1">
        <Label>Date</Label>
        <Input
          type="date" value={form.date}
          onChange={e => setForm(f => ({ ...f, date: e.target.value }))}
        />
      </div>
    </div>
  );
}

// ── Main Page ─────────────────────────────────────────────────
export default function Savings() {
  const [members, setMembers]           = useState<any[]>([]);
  const [allSavings, setAllSavings]     = useState<any[]>([]);
  const [monthSavings, setMonthSavings] = useState<any[]>([]);
  const [loading, setLoading]           = useState(true);

  // Selected month/year for the monthly view
  const [selMonth, setSelMonth] = useState(CURRENT_MONTH);
  const [selYear, setSelYear]   = useState(CURRENT_YEAR);

  // Add dialog
  const [showAdd, setShowAdd]   = useState(false);
  const [addForm, setAddForm]   = useState<SavingForm>({ ...EMPTY_FORM });
  const [addSaving, setAddSaving] = useState(false);

  // Delete confirm
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [deleting, setDeleting] = useState(false);

  // Active tab
  const [tab, setTab] = useState<"monthly" | "all">("monthly");

  useEffect(() => { loadAll(); }, []);

  useEffect(() => {
    loadMonthSavings(selMonth, selYear);
  }, [selMonth, selYear]);

  async function loadAll() {
    setLoading(true);
    try {
      const [mRes, sRes] = await Promise.all([
        membersApi.list(),
        savingsApi.list(),
      ]);
      setMembers(mRes.data || []);
      setAllSavings(sRes.data || []);
      await loadMonthSavings(selMonth, selYear);
    } catch (err: any) {
      toast.error(err.message || "Failed to load savings");
    } finally {
      setLoading(false);
    }
  }

  async function loadMonthSavings(month: number, year: number) {
    try {
      const res = await savingsApi.list({ month, year });
      setMonthSavings(res.data || []);
    } catch {
      setMonthSavings([]);
    }
  }

  function prevMonth() {
    if (selMonth === 1) { setSelMonth(12); setSelYear(y => y - 1); }
    else setSelMonth(m => m - 1);
  }
  function nextMonth() {
    const now = new Date();
    if (selYear > now.getFullYear() || (selYear === now.getFullYear() && selMonth >= now.getMonth() + 1)) return;
    if (selMonth === 12) { setSelMonth(1); setSelYear(y => y + 1); }
    else setSelMonth(m => m + 1);
  }

  async function handleAdd(e: React.FormEvent) {
    e.preventDefault();
    if (!addForm.member_id || !addForm.amount) {
      toast.error("Member and amount are required"); return;
    }
    setAddSaving(true);
    try {
      await savingsApi.create({
        member_id:    addForm.member_id,
        month:        Number(addForm.month),
        year:         Number(addForm.year),
        amount:       Number(addForm.amount),
        payment_mode: addForm.payment_mode,
        date:         addForm.date,
      });
      toast.success("Saving recorded!");
      setShowAdd(false);
      setAddForm({ ...EMPTY_FORM });
      loadAll();
    } catch (err: any) {
      toast.error(err.message || "Failed to record saving");
    } finally {
      setAddSaving(false);
    }
  }

  async function handleDelete() {
    if (!deleteId) return;
    setDeleting(true);
    try {
      await savingsApi.delete(deleteId);
      toast.success("Entry deleted");
      setDeleteId(null);
      loadAll();
    } catch (err: any) {
      toast.error(err.message || "Failed to delete");
    } finally {
      setDeleting(false);
    }
  }

  // ── Derived stats ─────────────────────────────────────────
  const totalAllTime    = allSavings.reduce((s, r) => s + Number(r.amount), 0);
  const totalThisMonth  = monthSavings.reduce((s, r) => s + Number(r.amount), 0);
  const avgPerMember    = members.length ? Math.round(totalAllTime / members.length) : 0;
  const paidThisMonth   = monthSavings.length;
  const pendingCount    = members.length - paidThisMonth;

  // Member-wise summary (all time)
  const memberSummary = members.map(m => {
    const mSavings = allSavings.filter(s => s.member_id === m.id);
    const total    = mSavings.reduce((s, r) => s + Number(r.amount), 0);
    const paidThis = monthSavings.some(s => s.member_id === m.id);
    return { ...m, total, contributions: mSavings.length, paidThisMonth: paidThis };
  }).sort((a, b) => b.total - a.total);

  if (loading) return (
    <DashboardLayout>
      <div className="flex justify-center py-24">
        <div className="w-8 h-8 rounded-full border-4 border-[#C2185B]/30 border-t-[#C2185B] animate-spin" />
      </div>
    </DashboardLayout>
  );

  return (
    <DashboardLayout>
      {/* Header */}
      <div className="flex items-center justify-between mb-6 flex-wrap gap-3">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Savings</h1>
          <p className="text-sm text-muted-foreground mt-0.5">Track monthly savings for all members</p>
        </div>
        <Button
          onClick={() => { setAddForm({ ...EMPTY_FORM }); setShowAdd(true); }}
          className="bg-[#C2185B] hover:bg-[#AD1457] text-white"
        >
          <Plus className="w-4 h-4 mr-2" /> Record Saving
        </Button>
      </div>

      {/* Stat Cards */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
        {[
          { icon: PiggyBank,    color: "#C2185B", label: "Total Group Savings",  value: `₹${totalAllTime.toLocaleString("en-IN")}`,   sub: "All time" },
          { icon: Calendar,     color: "#6A1B9A", label: "This Month",           value: `₹${totalThisMonth.toLocaleString("en-IN")}`, sub: `${MONTH_NAMES[selMonth-1]} ${selYear}` },
          { icon: Users,        color: "#0288D1", label: "Paid This Month",      value: `${paidThisMonth} / ${members.length}`,       sub: pendingCount > 0 ? `${pendingCount} pending` : "All paid ✓" },
          { icon: TrendingUp,   color: "#388E3C", label: "Avg per Member",       value: `₹${avgPerMember.toLocaleString("en-IN")}`,   sub: "All time average" },
        ].map(({ icon: Icon, color, label, value, sub }) => (
          <Card key={label} className="border-border/60 shadow-sm">
            <CardContent className="pt-4 pb-4">
              <div className="flex items-start gap-3">
                <div className="w-9 h-9 rounded-xl flex items-center justify-center shrink-0" style={{ backgroundColor: `${color}15` }}>
                  <Icon className="w-4 h-4" style={{ color }} />
                </div>
                <div>
                  <p className="text-xs text-muted-foreground">{label}</p>
                  <p className="text-xl font-bold text-gray-900 leading-tight">{value}</p>
                  <p className="text-xs text-muted-foreground">{sub}</p>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Tabs */}
      <div className="flex gap-1 bg-gray-100 rounded-xl p-1 mb-6 w-fit">
        {(["monthly", "all"] as const).map(t => (
          <button key={t} onClick={() => setTab(t)}
            className={`px-5 py-2 rounded-lg text-sm font-medium capitalize transition-all ${tab === t ? "bg-white shadow text-[#C2185B]" : "text-muted-foreground hover:text-foreground"}`}>
            {t === "monthly" ? "Monthly View" : "All Transactions"}
          </button>
        ))}
      </div>

      {/* ── MONTHLY VIEW ───────────────────────────────────── */}
      {tab === "monthly" && (
        <div className="space-y-5">
          {/* Month navigator */}
          <div className="flex items-center justify-between bg-white border border-border/60 rounded-xl px-4 py-3 shadow-sm">
            <button onClick={prevMonth} className="p-1.5 hover:bg-gray-100 rounded-lg transition-colors">
              <ChevronLeft className="w-5 h-5 text-muted-foreground" />
            </button>
            <div className="text-center">
              <p className="font-semibold text-gray-900">{MONTH_NAMES[selMonth - 1]} {selYear}</p>
              <p className="text-xs text-muted-foreground">{paidThisMonth} of {members.length} members paid</p>
            </div>
            <button onClick={nextMonth} className="p-1.5 hover:bg-gray-100 rounded-lg transition-colors">
              <ChevronRight className="w-5 h-5 text-muted-foreground" />
            </button>
          </div>

          {/* Progress bar */}
          <div className="bg-white border border-border/60 rounded-xl px-4 py-3 shadow-sm">
            <div className="flex justify-between text-sm mb-2">
              <span className="text-muted-foreground">Collection progress</span>
              <span className="font-medium text-[#C2185B]">
                ₹{totalThisMonth.toLocaleString("en-IN")} collected
              </span>
            </div>
            <div className="h-2.5 bg-gray-100 rounded-full overflow-hidden">
              <div
                className="h-full rounded-full bg-gradient-to-r from-[#C2185B] to-[#6A1B9A] transition-all"
                style={{ width: members.length ? `${(paidThisMonth / members.length) * 100}%` : "0%" }}
              />
            </div>
            <p className="text-xs text-muted-foreground mt-1.5">
              {members.length ? Math.round((paidThisMonth / members.length) * 100) : 0}% complete
            </p>
          </div>

          {/* Member payment status grid */}
          <Card className="border-border/60">
            <CardHeader className="pb-3">
              <CardTitle className="text-sm font-semibold flex items-center gap-2">
                <Users className="w-4 h-4 text-[#C2185B]" />
                Member Status — {MONTH_NAMES[selMonth - 1]} {selYear}
              </CardTitle>
            </CardHeader>
            <CardContent>
              {members.length === 0 ? (
                <p className="text-center text-muted-foreground py-8 text-sm">No members found</p>
              ) : (
                <div className="space-y-2">
                  {members.map(m => {
                    const entry = monthSavings.find(s => s.member_id === m.id);
                    return (
                      <div key={m.id} className={`flex items-center justify-between px-4 py-3 rounded-xl border transition-colors ${entry ? "bg-green-50/50 border-green-100" : "bg-orange-50/40 border-orange-100"}`}>
                        <div className="flex items-center gap-3">
                          <div className="w-9 h-9 rounded-full bg-gradient-to-br from-[#C2185B] to-[#6A1B9A] flex items-center justify-center text-white text-sm font-bold shrink-0">
                            {m.name.charAt(0)}
                          </div>
                          <div>
                            <Link to={`/members/${m.id}`} className="text-sm font-medium text-gray-900 hover:text-[#C2185B] transition-colors">
                              {m.name}
                            </Link>
                            <p className="text-xs text-muted-foreground capitalize">{m.role}</p>
                          </div>
                        </div>
                        <div className="flex items-center gap-3">
                          {entry ? (
                            <>
                              <div className="text-right">
                                <p className="text-sm font-semibold text-green-700">₹{Number(entry.amount).toLocaleString("en-IN")}</p>
                                <p className="text-xs text-muted-foreground capitalize">{entry.payment_mode}</p>
                              </div>
                              <CheckCircle2 className="w-5 h-5 text-green-500 shrink-0" />
                              <button onClick={() => setDeleteId(entry.id)} className="p-1 hover:bg-red-100 rounded-lg transition-colors">
                                <Trash2 className="w-3.5 h-3.5 text-red-400" />
                              </button>
                            </>
                          ) : (
                            <>
                              <span className="text-xs text-orange-600 font-medium">Not paid</span>
                              <AlertCircle className="w-5 h-5 text-orange-400 shrink-0" />
                              <button
                                onClick={() => {
                                  setAddForm({ ...EMPTY_FORM, member_id: m.id, month: String(selMonth), year: String(selYear) });
                                  setShowAdd(true);
                                }}
                                className="p-1 hover:bg-[#C2185B]/10 rounded-lg transition-colors"
                              >
                                <Plus className="w-3.5 h-3.5 text-[#C2185B]" />
                              </button>
                            </>
                          )}
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      )}

      {/* ── ALL TRANSACTIONS ──────────────────────────────── */}
      {tab === "all" && (
        <div className="space-y-5">
          {/* Member savings summary */}
          <Card className="border-border/60">
            <CardHeader className="pb-3">
              <CardTitle className="text-sm font-semibold flex items-center gap-2">
                <PiggyBank className="w-4 h-4 text-[#C2185B]" /> Member-wise Summary
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="overflow-x-auto">
                <Table>
                  <TableHeader>
                    <TableRow className="bg-gray-50">
                      <TableHead>Member</TableHead>
                      <TableHead>Contributions</TableHead>
                      <TableHead>Total Saved</TableHead>
                      <TableHead>This Month</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {memberSummary.map(m => (
                      <TableRow key={m.id} className="hover:bg-gray-50/50">
                        <TableCell>
                          <Link to={`/members/${m.id}`} className="flex items-center gap-2.5 hover:text-[#C2185B] transition-colors">
                            <div className="w-8 h-8 rounded-full bg-gradient-to-br from-[#C2185B] to-[#6A1B9A] flex items-center justify-center text-white text-xs font-bold shrink-0">
                              {m.name.charAt(0)}
                            </div>
                            <span className="font-medium">{m.name}</span>
                          </Link>
                        </TableCell>
                        <TableCell className="text-muted-foreground">{m.contributions} months</TableCell>
                        <TableCell className="font-semibold text-green-700">₹{m.total.toLocaleString("en-IN")}</TableCell>
                        <TableCell>
                          {m.paidThisMonth
                            ? <span className="text-xs bg-green-100 text-green-700 px-2 py-0.5 rounded-full">Paid</span>
                            : <span className="text-xs bg-orange-100 text-orange-600 px-2 py-0.5 rounded-full">Pending</span>
                          }
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </div>
            </CardContent>
          </Card>

          {/* All transactions */}
          <Card className="border-border/60">
            <CardHeader className="pb-3">
              <div className="flex items-center justify-between">
                <CardTitle className="text-sm font-semibold flex items-center gap-2">
                  <TrendingUp className="w-4 h-4 text-[#6A1B9A]" /> All Transactions
                </CardTitle>
                <span className="text-xs text-muted-foreground">{allSavings.length} entries</span>
              </div>
            </CardHeader>
            <CardContent>
              {allSavings.length === 0 ? (
                <div className="text-center py-16 text-muted-foreground">
                  <PiggyBank className="w-10 h-10 mx-auto mb-2 opacity-20" />
                  <p>No savings recorded yet</p>
                </div>
              ) : (
                <div className="overflow-x-auto">
                  <Table>
                    <TableHeader>
                      <TableRow className="bg-gray-50">
                        <TableHead>Member</TableHead>
                        <TableHead>Month</TableHead>
                        <TableHead>Amount</TableHead>
                        <TableHead>Mode</TableHead>
                        <TableHead>Date</TableHead>
                        <TableHead></TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {allSavings.map(s => (
                        <TableRow key={s.id} className="hover:bg-gray-50/50">
                          <TableCell className="font-medium">{s.member_name}</TableCell>
                          <TableCell className="text-muted-foreground">
                            {MONTH_NAMES[s.month - 1]} {s.year}
                          </TableCell>
                          <TableCell>
                            <span className="font-semibold text-green-700">₹{Number(s.amount).toLocaleString("en-IN")}</span>
                          </TableCell>
                          <TableCell>
                            <span className="text-xs capitalize bg-gray-100 text-gray-600 px-2 py-0.5 rounded-full">{s.payment_mode}</span>
                          </TableCell>
                          <TableCell className="text-muted-foreground text-sm">
                            {s.date ? new Date(s.date).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" }) : "—"}
                          </TableCell>
                          <TableCell>
                            <button onClick={() => setDeleteId(s.id)} className="p-1.5 hover:bg-red-50 rounded-lg transition-colors">
                              <Trash2 className="w-3.5 h-3.5 text-red-400" />
                            </button>
                          </TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </div>
              )}

              {/* Total footer */}
              {allSavings.length > 0 && (
                <div className="mt-4 p-3 bg-[#C2185B]/5 rounded-xl flex justify-between items-center">
                  <span className="text-sm text-muted-foreground">Grand Total</span>
                  <span className="text-lg font-bold text-[#C2185B]">₹{totalAllTime.toLocaleString("en-IN")}</span>
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      )}

      {/* ── Add Saving Dialog ─────────────────────────────── */}
      <Dialog open={showAdd} onOpenChange={o => !o && setShowAdd(false)}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-[#C2185B] to-[#6A1B9A] flex items-center justify-center">
                <PiggyBank className="w-4 h-4 text-white" />
              </div>
              Record Saving
            </DialogTitle>
          </DialogHeader>
          <form onSubmit={handleAdd} className="mt-1">
            <AddSavingForm members={members} form={addForm} setForm={setAddForm} />
            <div className="flex gap-3 justify-end pt-5 mt-2 border-t">
              <Button type="button" variant="outline" onClick={() => setShowAdd(false)}>Cancel</Button>
              <Button type="submit" className="bg-[#C2185B] hover:bg-[#AD1457] text-white" disabled={addSaving}>
                {addSaving ? "Saving..." : "Record Saving"}
              </Button>
            </div>
          </form>
        </DialogContent>
      </Dialog>

      {/* ── Delete Confirm Dialog ─────────────────────────── */}
      <Dialog open={!!deleteId} onOpenChange={o => !o && setDeleteId(null)}>
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2 text-red-600">
              <AlertCircle className="w-5 h-5" /> Delete Entry?
            </DialogTitle>
          </DialogHeader>
          <p className="text-sm text-muted-foreground py-2">
            This will permanently remove this saving entry. This cannot be undone.
          </p>
          <div className="flex gap-3 justify-end pt-2">
            <Button variant="outline" onClick={() => setDeleteId(null)}>Cancel</Button>
            <Button
              className="bg-red-500 hover:bg-red-600 text-white"
              onClick={handleDelete} disabled={deleting}
            >
              {deleting ? "Deleting..." : "Delete"}
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </DashboardLayout>
  );
}

// src/pages/Settings.tsx
import { useEffect, useState } from "react";
import { DashboardLayout } from "@/components/DashboardLayout";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Separator } from "@/components/ui/separator";
import {
  Globe, Landmark, Lock, Save, CheckCircle2,
  Building2, MapPin, Calendar, CreditCard, Hash,
} from "lucide-react";
import { shgApi, authApi } from "@/lib/api";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";

const SECTIONS = [
  { id: "shg",      label: "SHG Information",  icon: Globe     },
  { id: "bank",     label: "Bank Details",      icon: Landmark  },
  { id: "password", label: "Change Password",   icon: Lock      },
];

export default function SettingsPage() {
  const { user, shg: authShg, refreshAuth } = useAuth();

  // SHG form
  const [shgForm, setShgForm] = useState({
    name: "", registration_number: "", village: "",
    block: "", district: "", state: "", formation_date: "",
    bank_name: "", bank_account: "", ifsc: "",
  });
  const [shgSaving, setShgSaving] = useState(false);

  // Password form
  const [pwForm, setPwForm]   = useState({ current: "", next: "", confirm: "" });
  const [pwSaving, setPwSaving] = useState(false);

  const [activeSection, setActiveSection] = useState("shg");

  useEffect(() => {
    async function load() {
      try {
        const res = await shgApi.get();
        const d = res.data;
        setShgForm({
          name:                d.name                || "",
          registration_number: d.registration_number || "",
          village:             d.village             || "",
          block:               d.block               || "",
          district:            d.district            || "",
          state:               d.state               || "",
          formation_date:      d.formation_date ? d.formation_date.split("T")[0] : "",
          bank_name:           d.bank_name           || "",
          bank_account:        d.bank_account        || "",
          ifsc:                d.ifsc                || "",
        });
      } catch { /* shg not set up yet */ }
    }
    load();
  }, []);

  async function handleShgSave(e: React.FormEvent) {
    e.preventDefault();
    if (!shgForm.name.trim()) { toast.error("SHG name is required"); return; }
    setShgSaving(true);
    try {
      await shgApi.update(shgForm);
      await refreshAuth?.();
      toast.success("SHG information updated!");
    } catch (err: any) {
      toast.error(err.message || "Failed to save");
    } finally {
      setShgSaving(false);
    }
  }

  async function handlePasswordSave(e: React.FormEvent) {
    e.preventDefault();
    if (!pwForm.current) { toast.error("Enter your current password"); return; }
    if (pwForm.next.length < 6) { toast.error("New password must be at least 6 characters"); return; }
    if (pwForm.next !== pwForm.confirm) { toast.error("Passwords don't match"); return; }
    setPwSaving(true);
    try {
      await authApi.changePassword?.({ current: pwForm.current, newPassword: pwForm.next });
      toast.success("Password changed successfully!");
      setPwForm({ current: "", next: "", confirm: "" });
    } catch (err: any) {
      toast.error(err.message || "Failed to change password");
    } finally {
      setPwSaving(false);
    }
  }

  // ── Reusable field ────────────────────────────────────────
  function Field({
    label, value, onChange, type = "text", placeholder = "", disabled = false, icon: Icon,
  }: {
    label: string; value: string; onChange?: (v: string) => void;
    type?: string; placeholder?: string; disabled?: boolean; icon?: any;
  }) {
    return (
      <div className="space-y-1.5">
        <Label className="text-xs font-medium text-gray-600">{label}</Label>
        <div className="relative">
          {Icon && (
            <div className="absolute left-3 top-1/2 -translate-y-1/2 pointer-events-none">
              <Icon className="w-3.5 h-3.5 text-muted-foreground" />
            </div>
          )}
          <Input
            type={type}
            value={value}
            onChange={e => onChange?.(e.target.value)}
            placeholder={placeholder}
            disabled={disabled}
            className={`${Icon ? "pl-9" : ""} border-gray-200 focus:border-[#C2185B] focus:ring-[#C2185B]/10 disabled:bg-gray-50 text-sm`}
          />
        </div>
      </div>
    );
  }

  return (
    <DashboardLayout>
      {/* Header */}
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-gray-900">Settings</h1>
        <p className="text-sm text-muted-foreground mt-0.5">Manage your SHG profile and account preferences</p>
      </div>

      <div className="flex flex-col lg:flex-row gap-6">

        {/* ── Sidebar nav ───────────────────────────────────── */}
        <div className="lg:w-56 shrink-0">
          <Card className="border-border/50 shadow-sm p-2">
            <nav className="space-y-0.5">
              {SECTIONS.map(({ id, label, icon: Icon }) => (
                <button key={id} onClick={() => setActiveSection(id)}
                  className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${
                    activeSection === id
                      ? "bg-gradient-to-r from-[#C2185B]/10 to-[#6A1B9A]/5 text-[#C2185B]"
                      : "text-gray-600 hover:bg-gray-50 hover:text-gray-900"
                  }`}>
                  <Icon className="w-4 h-4 shrink-0" />
                  {label}
                </button>
              ))}
            </nav>
          </Card>

          {/* Account info card */}
          <Card className="border-border/50 shadow-sm mt-4">
            <CardContent className="p-4">
              <div className="flex items-center gap-3 mb-3">
                <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-[#C2185B] to-[#6A1B9A] flex items-center justify-center text-white font-bold shrink-0">
                  {user?.name?.charAt(0) || "U"}
                </div>
                <div className="min-w-0">
                  <p className="text-sm font-semibold text-gray-900 truncate">{user?.name}</p>
                  <p className="text-xs text-muted-foreground truncate">{user?.email}</p>
                </div>
              </div>
              <div className="text-xs text-muted-foreground space-y-1">
                <p className="flex items-center gap-1.5">
                  <CheckCircle2 className="w-3 h-3 text-green-500" /> SHG Leader
                </p>
                {authShg?.name && (
                  <p className="flex items-center gap-1.5">
                    <Building2 className="w-3 h-3 text-[#C2185B]" />
                    <span className="truncate">{authShg.name}</span>
                  </p>
                )}
              </div>
            </CardContent>
          </Card>
        </div>

        {/* ── Main content ──────────────────────────────────── */}
        <div className="flex-1 min-w-0">

          {/* SHG Information */}
          {activeSection === "shg" && (
            <Card className="border-border/50 shadow-sm">
              <CardHeader className="px-6 pt-6 pb-4">
                <CardTitle className="text-base flex items-center gap-2">
                  <div className="w-8 h-8 rounded-lg bg-[#C2185B]/10 flex items-center justify-center">
                    <Globe className="w-4 h-4 text-[#C2185B]" />
                  </div>
                  SHG Information
                </CardTitle>
                <p className="text-sm text-muted-foreground mt-1">
                  Update your group's name, location and registration details
                </p>
              </CardHeader>
              <CardContent className="px-6 pb-6">
                <form onSubmit={handleShgSave} className="space-y-5">
                  {/* Basic info */}
                  <div>
                    <p className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-3">Basic Info</p>
                    <div className="grid sm:grid-cols-2 gap-4">
                      <Field label="SHG Name *" value={shgForm.name}
                        onChange={v => setShgForm(f => ({ ...f, name: v }))}
                        placeholder="e.g. Shakti Mahila Mandal" icon={Building2} />
                      <Field label="Registration Number" value={shgForm.registration_number}
                        onChange={v => setShgForm(f => ({ ...f, registration_number: v }))}
                        placeholder="e.g. SHG/2021/001" icon={Hash} />
                      <Field label="Formation Date" value={shgForm.formation_date}
                        onChange={v => setShgForm(f => ({ ...f, formation_date: v }))}
                        type="date" icon={Calendar} />
                    </div>
                  </div>

                  <Separator />

                  {/* Location */}
                  <div>
                    <p className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-3">Location</p>
                    <div className="grid sm:grid-cols-2 gap-4">
                      <Field label="Village" value={shgForm.village}
                        onChange={v => setShgForm(f => ({ ...f, village: v }))}
                        placeholder="e.g. Rampur" icon={MapPin} />
                      <Field label="Block" value={shgForm.block}
                        onChange={v => setShgForm(f => ({ ...f, block: v }))}
                        placeholder="e.g. Karjat" />
                      <Field label="District" value={shgForm.district}
                        onChange={v => setShgForm(f => ({ ...f, district: v }))}
                        placeholder="e.g. Ahmednagar" />
                      <Field label="State" value={shgForm.state}
                        onChange={v => setShgForm(f => ({ ...f, state: v }))}
                        placeholder="e.g. Maharashtra" />
                    </div>
                  </div>

                  <div className="flex justify-end pt-2">
                    <Button type="submit" disabled={shgSaving}
                      className="bg-[#C2185B] hover:bg-[#AD1457] text-white gap-2">
                      <Save className="w-4 h-4" />
                      {shgSaving ? "Saving..." : "Save Changes"}
                    </Button>
                  </div>
                </form>
              </CardContent>
            </Card>
          )}

          {/* Bank Details */}
          {activeSection === "bank" && (
            <Card className="border-border/50 shadow-sm">
              <CardHeader className="px-6 pt-6 pb-4">
                <CardTitle className="text-base flex items-center gap-2">
                  <div className="w-8 h-8 rounded-lg bg-[#6A1B9A]/10 flex items-center justify-center">
                    <Landmark className="w-4 h-4 text-[#6A1B9A]" />
                  </div>
                  Bank Details
                </CardTitle>
                <p className="text-sm text-muted-foreground mt-1">
                  SHG's linked bank account for loan disbursements and savings
                </p>
              </CardHeader>
              <CardContent className="px-6 pb-6">
                <form onSubmit={handleShgSave} className="space-y-4">
                  <div className="grid sm:grid-cols-2 gap-4">
                    <Field label="Bank Name" value={shgForm.bank_name}
                      onChange={v => setShgForm(f => ({ ...f, bank_name: v }))}
                      placeholder="e.g. State Bank of India" icon={Landmark} />
                    <Field label="Account Number" value={shgForm.bank_account}
                      onChange={v => setShgForm(f => ({ ...f, bank_account: v }))}
                      placeholder="e.g. 30209876543210" icon={CreditCard} />
                    <Field label="IFSC Code" value={shgForm.ifsc}
                      onChange={v => setShgForm(f => ({ ...f, ifsc: v.toUpperCase() }))}
                      placeholder="e.g. SBIN0031204" />
                  </div>

                  {/* Read-only info box */}
                  {shgForm.bank_account && (
                    <div className="rounded-xl bg-blue-50 border border-blue-100 p-4 text-sm text-blue-800 mt-2">
                      <p className="font-medium mb-1">Current linked account</p>
                      <p className="text-xs text-blue-600">
                        {shgForm.bank_name || "Bank"} · ****{shgForm.bank_account.slice(-4)} · {shgForm.ifsc || "—"}
                      </p>
                    </div>
                  )}

                  <div className="flex justify-end pt-2">
                    <Button type="submit" disabled={shgSaving}
                      className="bg-[#C2185B] hover:bg-[#AD1457] text-white gap-2">
                      <Save className="w-4 h-4" />
                      {shgSaving ? "Saving..." : "Save Bank Details"}
                    </Button>
                  </div>
                </form>
              </CardContent>
            </Card>
          )}

          {/* Change Password */}
          {activeSection === "password" && (
            <Card className="border-border/50 shadow-sm">
              <CardHeader className="px-6 pt-6 pb-4">
                <CardTitle className="text-base flex items-center gap-2">
                  <div className="w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center">
                    <Lock className="w-4 h-4 text-gray-600" />
                  </div>
                  Change Password
                </CardTitle>
                <p className="text-sm text-muted-foreground mt-1">
                  Update your login password. Minimum 6 characters.
                </p>
              </CardHeader>
              <CardContent className="px-6 pb-6">
                <form onSubmit={handlePasswordSave} className="space-y-4 max-w-sm">
                  <Field label="Current Password" value={pwForm.current} type="password"
                    onChange={v => setPwForm(f => ({ ...f, current: v }))}
                    placeholder="Enter current password" icon={Lock} />
                  <Field label="New Password" value={pwForm.next} type="password"
                    onChange={v => setPwForm(f => ({ ...f, next: v }))}
                    placeholder="Min. 6 characters" icon={Lock} />
                  <Field label="Confirm New Password" value={pwForm.confirm} type="password"
                    onChange={v => setPwForm(f => ({ ...f, confirm: v }))}
                    placeholder="Repeat new password" icon={Lock} />

                  {pwForm.next && pwForm.confirm && pwForm.next !== pwForm.confirm && (
                    <p className="text-xs text-red-500">Passwords don't match</p>
                  )}

                  <div className="flex justify-end pt-2">
                    <Button type="submit" disabled={pwSaving}
                      className="bg-[#C2185B] hover:bg-[#AD1457] text-white gap-2">
                      <Lock className="w-4 h-4" />
                      {pwSaving ? "Changing..." : "Change Password"}
                    </Button>
                  </div>
                </form>
              </CardContent>
            </Card>
          )}

        </div>
      </div>
    </DashboardLayout>
  );
}

// src/pages/Setup.tsx
// Shown once after signup to collect SHG details.
import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { shgApi } from '@/lib/api';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { HeartHandshake } from 'lucide-react';
import { toast } from 'sonner';

export default function Setup() {
  const { refreshUser } = useAuth();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({
    name: '',
    registration_number: '',
    village: '',
    block: '',
    district: '',
    state: 'Rajasthan',
    formation_date: '',
    bank_name: '',
    bank_account: '',
    ifsc: '',
  });

  const set = (field: string) => (e: React.ChangeEvent<HTMLInputElement>) =>
    setForm(prev => ({ ...prev, [field]: e.target.value }));

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!form.name) return toast.error('SHG name is required');
    setLoading(true);
    try {
      await shgApi.setup(form);
      await refreshUser();
      toast.success('SHG profile created!');
      navigate('/dashboard');
    } catch (err: any) {
      toast.error(err.message || 'Setup failed');
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-[#FCE4EC] to-[#EDE7F6] flex items-center justify-center p-4">
      <div className="w-full max-w-lg bg-white rounded-2xl shadow-lg overflow-hidden">
        <div className="bg-gradient-to-r from-[#C2185B] to-[#6A1B9A] p-6 text-white text-center">
          <HeartHandshake className="w-10 h-10 mx-auto mb-2" />
          <h1 className="text-xl font-bold">Set Up Your SHG</h1>
          <p className="text-white/80 text-sm">Enter your group details to get started</p>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div className="col-span-2 space-y-1">
              <Label>SHG Name *</Label>
              <Input placeholder="e.g. Asha Mahila Mandal" value={form.name} onChange={set('name')} required />
            </div>
            <div className="space-y-1">
              <Label>Registration Number</Label>
              <Input placeholder="Reg. no." value={form.registration_number} onChange={set('registration_number')} />
            </div>
            <div className="space-y-1">
              <Label>Formation Date</Label>
              <Input type="date" value={form.formation_date} onChange={set('formation_date')} />
            </div>
            <div className="space-y-1">
              <Label>Village</Label>
              <Input placeholder="Village name" value={form.village} onChange={set('village')} />
            </div>
            <div className="space-y-1">
              <Label>Block</Label>
              <Input placeholder="Block" value={form.block} onChange={set('block')} />
            </div>
            <div className="space-y-1">
              <Label>District</Label>
              <Input placeholder="District" value={form.district} onChange={set('district')} />
            </div>
            <div className="space-y-1">
              <Label>State</Label>
              <Input value={form.state} onChange={set('state')} />
            </div>
            <div className="col-span-2 border-t pt-4">
              <p className="text-sm font-medium text-muted-foreground mb-3">Bank Details (optional)</p>
            </div>
            <div className="space-y-1">
              <Label>Bank Name</Label>
              <Input placeholder="Bank name" value={form.bank_name} onChange={set('bank_name')} />
            </div>
            <div className="space-y-1">
              <Label>Account Number</Label>
              <Input placeholder="Account no." value={form.bank_account} onChange={set('bank_account')} />
            </div>
            <div className="col-span-2 space-y-1">
              <Label>IFSC Code</Label>
              <Input placeholder="IFSC" value={form.ifsc} onChange={set('ifsc')} />
            </div>
          </div>

          <Button
            type="submit"
            className="w-full bg-[#C2185B] hover:bg-[#AD1457] text-white"
            disabled={loading}
          >
            {loading ? 'Creating SHG...' : 'Create SHG Profile →'}
          </Button>
        </form>
      </div>
    </div>
  );
}

// src/pages/Signup.tsx
import { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/components/ui/tabs';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { HeartHandshake, Eye, EyeOff } from 'lucide-react';
import { authApi } from '@/lib/api';
import { toast } from 'sonner';

export default function Signup() {
  const { signup, memberSignup } = useAuth();
  const navigate = useNavigate();
  const [role, setRole] = useState<'leader' | 'member'>('leader');
  
  // Shared
  const [name, setName] = useState('');
  const [password, setPassword] = useState('');
  const [showPw, setShowPw] = useState(false);
  const [loading, setLoading] = useState(false);

  // Leader Specific
  const [email, setEmail] = useState('');

  // Member Specific
  const [phone, setPhone] = useState('');
  const [aadhar, setAadhar] = useState('');
  const [district, setDistrict] = useState('');
  const [shgId, setShgId] = useState('');
  const [shgList, setShgList] = useState<{ id: string; name: string }[]>([]);

  useEffect(() => {
    if (role === 'member' && district.length > 2) {
      // Small delay to avoid querying on every keystroke
      const timer = setTimeout(() => {
        authApi.getShgList(district)
          .then(res => setShgList(res.shgs))
          .catch(err => console.error("Failed to fetch SHGs", err));
      }, 500);
      return () => clearTimeout(timer);
    } else {
      setShgList([]);
      setShgId(''); // reset selected SHG if list clears
    }
  }, [role, district]);

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (password.length < 6) {
      toast.error('Password must be at least 6 characters');
      return;
    }
    
    setLoading(true);
    try {
      if (role === 'leader') {
        await signup(name, email, password);
        navigate('/setup'); // go to SHG setup
      } else {
        if (!shgId) {
          toast.error("Please select an SHG");
          setLoading(false);
          return;
        }
        await memberSignup(name, phone, aadhar, shgId, password);
        navigate('/member/loans');
      }
    } catch (err: any) {
      toast.error(err.message || 'Signup failed');
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-[#FCE4EC] to-[#EDE7F6] flex items-center justify-center p-4">
      <div className="w-full max-w-md bg-white rounded-2xl shadow-lg overflow-hidden">
        <div className="bg-gradient-to-r from-[#C2185B] to-[#6A1B9A] p-8 text-white text-center">
          <HeartHandshake className="w-12 h-12 mx-auto mb-3" />
          <h1 className="text-2xl font-bold">SakhiSahyog</h1>
          <p className="text-white/80 text-sm mt-1">Join thousands of empowered women</p>
        </div>

        <div className="p-8 pb-4">
          <Tabs value={role} onValueChange={(v) => setRole(v as 'leader' | 'member')} className="w-full">
            <TabsList className="grid w-full grid-cols-2 mb-6 bg-pink-50">
              <TabsTrigger value="leader" className="data-[state=active]:bg-[#C2185B] data-[state=active]:text-white">SHG Leader</TabsTrigger>
              <TabsTrigger value="member" className="data-[state=active]:bg-[#C2185B] data-[state=active]:text-white">SHG Member</TabsTrigger>
            </TabsList>
          </Tabs>
        </div>

        <form onSubmit={handleSubmit} className="px-8 pb-8 space-y-4">
          <h2 className="text-xl font-semibold text-center text-gray-800">
            {role === 'leader' ? 'Leader Registration' : 'Member Registration'}
          </h2>

          <div className="space-y-1">
            <Label htmlFor="name">Full Name</Label>
            <Input
              id="name"
              placeholder="e.g. Priya Sharma"
              value={name}
              onChange={e => setName(e.target.value)}
              required
            />
          </div>

          {role === 'leader' ? (
            <div className="space-y-1">
              <Label htmlFor="email">Email</Label>
              <Input
                id="email"
                type="email"
                placeholder="priya@example.com"
                value={email}
                onChange={e => setEmail(e.target.value)}
                required
              />
            </div>
          ) : (
            <>
              <div className="space-y-1">
                <Label htmlFor="phone">Phone Number</Label>
                <Input
                  id="phone"
                  type="tel"
                  placeholder="e.g. 9876543210"
                  value={phone}
                  onChange={e => setPhone(e.target.value)}
                  required
                />
              </div>
              <div className="space-y-1">
                <Label htmlFor="aadhar">Aadhaar Number</Label>
                <Input
                  id="aadhar"
                  type="text"
                  placeholder="Your 12-digit Aadhaar"
                  value={aadhar}
                  onChange={e => setAadhar(e.target.value)}
                  required
                />
              </div>
              <div className="space-y-1">
                <Label htmlFor="district">District</Label>
                <Input
                  id="district"
                  type="text"
                  placeholder="e.g. Pune"
                  value={district}
                  onChange={e => setDistrict(e.target.value)}
                  required
                />
              </div>
              <div className="space-y-1">
                <Label>Select Self Help Group (SHG)</Label>
                <Select value={shgId} onValueChange={setShgId} disabled={shgList.length === 0} required>
                  <SelectTrigger className="w-full">
                    <SelectValue 
                      placeholder={
                        district.length < 3 
                          ? "Type at least 3 letters of district" 
                          : shgList.length === 0 
                            ? "No SHGs found" 
                            : "Choose your SHG"
                      } 
                    />
                  </SelectTrigger>
                  <SelectContent>
                    {shgList.map(shg => (
                      <SelectItem key={shg.id} value={shg.id}>
                        {shg.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </>
          )}

          <div className="space-y-1">
            <Label htmlFor="password">Password</Label>
            <div className="relative">
              <Input
                id="password"
                type={showPw ? 'text' : 'password'}
                placeholder="min. 6 characters"
                value={password}
                onChange={e => setPassword(e.target.value)}
                required
              />
              <button
                type="button"
                onClick={() => setShowPw(v => !v)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
              >
                {showPw ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              </button>
            </div>
          </div>

          <Button
            type="submit"
            className="w-full bg-[#C2185B] hover:bg-[#AD1457] text-white mt-4"
            disabled={loading}
          >
            {loading ? 'Registering...' : 'Complete Registration'}
          </Button>

          <p className="text-center text-sm text-muted-foreground">
            Already have an account?{' '}
            <Link to="/login" className="text-[#C2185B] font-medium hover:underline">
              Sign in
            </Link>
          </p>
        </form>
      </div>
    </div>
  );
}

// src/pages/admin/AdminDashboard.tsx
import { useEffect, useState } from 'react';
import { adminApi } from '@/lib/api';
import { Users, AlertCircle, Calendar, MapPin, Loader2, IndianRupee, Landmark } from 'lucide-react';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog';

interface SHG {
  id: string;
  name: string;
  village: string;
  block: string;
  district: string;
  state: string;
  formation_date: string;
  member_count: number;
}

interface SHGDetails {
  shg: any;
  total_members: number;
  office_bearers: {
    president: any | null;
    secretary: any | null;
    treasurer: any | null;
  };
  financials: {
    total_savings: number;
    active_loans_count: number;
    active_loans_total: number;
  };
}

export default function AdminDashboard() {
  const [shgs, setShgs] = useState<SHG[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // Modal State
  const [selectedShgId, setSelectedShgId] = useState<string | null>(null);
  const [shgDetails, setShgDetails] = useState<SHGDetails | null>(null);
  const [detailsLoading, setDetailsLoading] = useState(false);

  useEffect(() => {
    async function loadShgs() {
      try {
        const res = await adminApi.getShgs();
        setShgs(res.data);
      } catch (err: any) {
        setError(err.message || 'Failed to load SHGs');
      } finally {
        setLoading(false);
      }
    }
    loadShgs();
  }, []);

  useEffect(() => {
    if (!selectedShgId) {
      setShgDetails(null);
      return;
    }

    async function loadDetails() {
      setDetailsLoading(true);
      try {
        const res = await adminApi.getShgDetails(selectedShgId!);
        setShgDetails(res.data);
      } catch (err: any) {
        console.error("Failed to load details", err);
      } finally {
        setDetailsLoading(false);
      }
    }
    loadDetails();
  }, [selectedShgId]);

  if (loading) {
    return (
      <div className="flex justify-center p-12">
        <div className="w-8 h-8 rounded-full border-4 border-[#C2185B]/30 border-t-[#C2185B] animate-spin" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-50 text-red-600 p-4 rounded-lg flex items-center gap-3">
        <AlertCircle className="w-5 h-5" />
        <p>{error}</p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between md:items-end gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-800">SHG Directory</h1>
          <p className="text-gray-500 text-sm">Overview of all Self Help Groups in your jurisdiction</p>
        </div>
        <div className="bg-[#FFF5F7] text-[#880E4F] px-4 py-2 rounded-lg font-medium text-sm flex items-center gap-2 border border-[#FCE4EC]">
          <Users className="w-4 h-4 text-[#C2185B]" />
          Total SHGs: {shgs.length}
        </div>
      </div>

      <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
        {shgs.map((shg) => (
          <div key={shg.id} className="bg-white p-5 rounded-xl shadow-sm border border-gray-100 hover:shadow-md hover:border-[#C2185B]/20 transition-all flex flex-col">
            <h3 className="font-semibold text-lg text-gray-800 break-words">{shg.name}</h3>

            <div className="mt-4 space-y-2 text-sm text-gray-600 flex-1">
              <div className="flex items-start gap-2">
                <MapPin className="w-4 h-4 mt-0.5 shrink-0 text-[#C2185B]/60" />
                <span>
                  {shg.village}, {shg.block}<br />
                  {shg.district}, {shg.state}
                </span>
              </div>

              <div className="flex items-center gap-2">
                <Calendar className="w-4 h-4 shrink-0 text-[#C2185B]/60" />
                <span>Formed: {new Date(shg.formation_date).toLocaleDateString()}</span>
              </div>

              <div className="flex items-center gap-2">
                <Users className="w-4 h-4 shrink-0 text-[#C2185B]/60" />
                <span>Members: <span className="font-medium text-gray-900">{shg.member_count}</span></span>
              </div>
            </div>

            <div className="mt-5 pt-4 border-t border-gray-100 flex gap-2">
              <button 
                onClick={() => setSelectedShgId(shg.id)}
                className="text-[#C2185B] font-medium text-sm hover:underline flex items-center gap-1"
              >
                View Details <span aria-hidden="true">&rarr;</span>
              </button>
            </div>
          </div>
        ))}

        {shgs.length === 0 && (
          <div className="col-span-full py-12 text-center text-gray-500 bg-white border border-gray-200 border-dashed rounded-xl">
            No SHGs found in your area.
          </div>
        )}
      </div>

      <Dialog open={!!selectedShgId} onOpenChange={(open) => !open && setSelectedShgId(null)}>
        <DialogContent className="max-w-2xl bg-white border-none shadow-2xl overflow-hidden p-0">
          {detailsLoading || !shgDetails ? (
            <div className="p-12 flex justify-center items-center flex-col gap-4">
              <Loader2 className="w-8 h-8 text-[#C2185B] animate-spin" />
              <p className="text-gray-500 text-sm">Loading SHG details...</p>
            </div>
          ) : (
            <>
              <div className="bg-gradient-to-r from-[#C2185B] to-[#6A1B9A] p-6 text-white">
                <DialogHeader>
                  <DialogTitle className="text-2xl font-bold">{shgDetails.shg.name}</DialogTitle>
                  <DialogDescription className="text-white/80 mt-1">
                    {shgDetails.shg.village}, {shgDetails.shg.district}
                  </DialogDescription>
                </DialogHeader>
              </div>

              <div className="p-6 space-y-6 max-h-[70vh] overflow-y-auto">
                {/* Financials highlight */}
                <div className="grid grid-cols-2 gap-4">
                  <div className="bg-green-50 rounded-xl p-4 border border-green-100">
                    <div className="flex items-center gap-2 text-green-700 font-medium mb-1 text-sm">
                      <IndianRupee className="w-4 h-4" /> Total Savings
                    </div>
                    <p className="text-2xl font-bold text-gray-900">
                      ₹{shgDetails.financials.total_savings.toLocaleString('en-IN')}
                    </p>
                  </div>
                  <div className="bg-blue-50 rounded-xl p-4 border border-blue-100">
                    <div className="flex items-center gap-2 text-blue-700 font-medium mb-1 text-sm">
                      <Landmark className="w-4 h-4" /> Active Loans ({shgDetails.financials.active_loans_count})
                    </div>
                    <p className="text-2xl font-bold text-gray-900">
                      ₹{shgDetails.financials.active_loans_total.toLocaleString('en-IN')}
                    </p>
                  </div>
                </div>

                {/* Office Bearers */}
                <div>
                  <h4 className="text-sm font-semibold text-gray-900 mb-3 border-b pb-2">Office Bearers</h4>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                    {[
                      { role: 'President', color: 'bg-pink-100 text-[#C2185B]', data: shgDetails.office_bearers.president },
                      { role: 'Secretary', color: 'bg-purple-100 text-[#6A1B9A]', data: shgDetails.office_bearers.secretary },
                      { role: 'Treasurer', color: 'bg-blue-100 text-[#0288D1]', data: shgDetails.office_bearers.treasurer }
                    ].map((item) => (
                      <div key={item.role} className="bg-gray-50 rounded-xl p-4 border border-gray-100">
                        <span className={`text-xs font-semibold px-2 py-0.5 rounded-full ${item.color} mb-2 inline-block`}>
                          {item.role}
                        </span>
                        {item.data ? (
                          <>
                            <p className="font-medium text-gray-900 mt-1 truncate">{item.data.name}</p>
                            <p className="text-xs text-gray-500 mt-0.5">{item.data.phone || 'No phone recorded'}</p>
                          </>
                        ) : (
                          <p className="text-sm text-gray-400 mt-1 italic">Not assigned</p>
                        )}
                      </div>
                    ))}
                  </div>
                </div>

                {/* Additional Details */}
                <div>
                  <h4 className="text-sm font-semibold text-gray-900 mb-3 border-b pb-2">Registration Details</h4>
                  <div className="grid grid-cols-2 gap-y-3 text-sm">
                    <div>
                      <span className="text-gray-500">Bank Name</span>
                      <p className="font-medium text-gray-900">{shgDetails.shg.bank_name || '—'}</p>
                    </div>
                    <div>
                      <span className="text-gray-500">Total Registered Members</span>
                      <p className="font-medium text-gray-900">{shgDetails.total_members}</p>
                    </div>
                  </div>
                </div>

              </div>
            </>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

// src/pages/admin/AdminLogin.tsx
import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAdminAuth } from '@/contexts/AdminAuthContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { ShieldCheck, Eye, EyeOff } from 'lucide-react';
import { toast } from 'sonner';

export default function AdminLogin() {
  const { login } = useAdminAuth();
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPw, setShowPw] = useState(false);
  const [loading, setLoading] = useState(false);

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setLoading(true);
    try {
      await login(email, password);
      navigate('/admin/dashboard');
    } catch (err: any) {
      toast.error(err.message || 'Admin login failed');
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-[#FCE4EC] to-[#EDE7F6] flex items-center justify-center p-4">
      <div className="w-full max-w-md bg-white rounded-2xl shadow-xl overflow-hidden border border-gray-100">
        <div className="bg-gradient-to-r from-[#C2185B] to-[#6A1B9A] p-8 text-white text-center">
          <ShieldCheck className="w-12 h-12 mx-auto mb-3" />
          <h1 className="text-2xl font-bold tracking-tight">System Admin</h1>
          <p className="text-white/80 text-sm mt-1">Authorized Personnel Only</p>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-5 bg-white">
          <div className="space-y-1">
            <Label htmlFor="email" className="text-gray-700">Admin Email</Label>
            <Input
              id="email"
              type="email"
              placeholder="admin@example.com"
              value={email}
              onChange={e => setEmail(e.target.value)}
              required
              className="bg-gray-50 focus:bg-white"
            />
          </div>

          <div className="space-y-1">
            <Label htmlFor="password" className="text-gray-700">Password</Label>
            <div className="relative">
              <Input
                id="password"
                type={showPw ? 'text' : 'password'}
                placeholder="••••••••"
                value={password}
                onChange={e => setPassword(e.target.value)}
                required
                className="bg-white"
              />
              <button
                type="button"
                onClick={() => setShowPw(v => !v)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 focus:outline-none"
              >
                {showPw ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              </button>
            </div>
          </div>

          <Button
            type="submit"
            className="w-full bg-[#C2185B] hover:bg-[#AD1457] text-white"
            disabled={loading}
          >
            {loading ? 'Authenticating...' : 'Secure Login'}
          </Button>

          <p className="text-center text-sm text-gray-500 mt-4">
            New Admin? <Link to="/admin/signup" className="text-[#C2185B] hover:underline font-medium">Register here</Link>
          </p>
          <p className="text-center text-xs text-gray-400 mt-2">
            Return to <Link to="/" className="text-gray-500 hover:text-gray-700 hover:underline">Public Portal</Link>
          </p>
        </form>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { ShieldCheck, Eye, EyeOff } from 'lucide-react';
import { toast } from 'sonner';

export default function AdminSignup() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    name: '',
    phone_number: '',
    email: '',
    password: '',
    state: '',
    district: ''
  });
  const [showPw, setShowPw] = useState(false);
  const [loading, setLoading] = useState(false);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData(prev => ({
      ...prev,
      [e.target.id]: e.target.value
    }));
  };

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await fetch('http://localhost:3001/api/admin/signup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      });

      const data = await res.json();

      if (!res.ok || !data.success) {
        throw new Error(data.error || 'Signup failed');
      }

      toast.success('Admin account created successfully');
      navigate('/admin/dashboard');
    } catch (err: any) {
      toast.error(err.message || 'Admin signup failed');
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-[#FCE4EC] to-[#EDE7F6] flex items-center justify-center p-4">
      <div className="w-full max-w-lg bg-white rounded-2xl shadow-xl overflow-hidden border border-gray-100 my-8">
        <div className="bg-gradient-to-r from-[#C2185B] to-[#6A1B9A] p-8 text-white text-center">
          <ShieldCheck className="w-12 h-12 mx-auto mb-3" />
          <h1 className="text-2xl font-bold tracking-tight">Admin Registration</h1>
          <p className="text-white/80 text-sm mt-1">Create an account for your district</p>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-5 bg-white">

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-1">
              <Label htmlFor="name" className="text-gray-700">Full Name</Label>
              <Input
                id="name"
                placeholder="Riya Koli"
                value={formData.name}
                onChange={handleChange}
                required
                className="bg-gray-50 focus:bg-white"
              />
            </div>
            <div className="space-y-1">
              <Label htmlFor="phone_number" className="text-gray-700">Phone Number</Label>
              <Input
                id="phone_number"
                type="tel"
                placeholder="+91 9876543210"
                value={formData.phone_number}
                onChange={handleChange}
                required
                className="bg-gray-50 focus:bg-white"
              />
            </div>
          </div>

          <div className="space-y-1">
            <Label htmlFor="email" className="text-gray-700">Admin Email</Label>
            <Input
              id="email"
              type="email"
              placeholder="admin@example.com"
              value={formData.email}
              onChange={handleChange}
              required
              className="bg-gray-50 focus:bg-white"
            />
          </div>

          <div className="space-y-1">
            <Label htmlFor="password" className="text-gray-700">Password</Label>
            <div className="relative">
              <Input
                id="password"
                type={showPw ? 'text' : 'password'}
                placeholder="••••••••"
                value={formData.password}
                onChange={handleChange}
                required
                className="bg-white"
              />
              <button
                type="button"
                onClick={() => setShowPw(v => !v)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 focus:outline-none"
              >
                {showPw ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-1">
              <Label htmlFor="state" className="text-gray-700">State</Label>
              <Input
                id="state"
                placeholder="Maharashtra"
                value={formData.state}
                onChange={handleChange}
                required
                className="bg-gray-50 focus:bg-white"
              />
            </div>
            <div className="space-y-1">
              <Label htmlFor="district" className="text-gray-700">District Assigned</Label>
              <Input
                id="district"
                placeholder="Pune"
                value={formData.district}
                onChange={handleChange}
                required
                className="bg-gray-50 focus:bg-white"
              />
            </div>
          </div>

          <Button
            type="submit"
            className="w-full bg-[#C2185B] hover:bg-[#AD1457] text-white shadow-md transition-all mt-4"
            disabled={loading}
          >
            {loading ? 'Creating Account...' : 'Register'}
          </Button>

          <p className="text-center text-sm text-gray-500 mt-4">
            Already have an account? <Link to="/admin/login" className="text-[#C2185B] hover:underline font-medium">Log in</Link>
          </p>
        </form>
      </div>
    </div>
  );
}

// src/pages/admin/SchemePosting.tsx
import { useEffect, useState } from 'react';
import { adminApi } from '@/lib/api';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { toast } from 'sonner';
import { FileText, Calendar, PlusCircle } from 'lucide-react';

interface Scheme {
  id: string;
  title: string;
  description: string;
  admin_email: string;
  created_at: string;
}

export default function SchemePosting() {
  const [schemes, setSchemes] = useState<Scheme[]>([]);
  const [loading, setLoading] = useState(true);

  // Form state
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [submitting, setSubmitting] = useState(false);

  async function loadSchemes() {
    try {
      const res = await adminApi.getSchemes();
      setSchemes(res.data);
    } catch (err: any) {
      toast.error('Failed to load schemes: ' + (err.message || 'Unknown error'));
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    loadSchemes();
  }, []);

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!title.trim() || !description.trim()) {
      toast.error('Please fill in both title and description');
      return;
    }

    setSubmitting(true);
    try {
      await adminApi.postScheme({ title, description });
      toast.success('Scheme posted successfully!');
      setTitle('');
      setDescription('');
      loadSchemes(); // Refresh list
    } catch (err: any) {
      toast.error(err.message || 'Failed to post scheme');
    } finally {
      setSubmitting(false);
    }
  }

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div>
        <h1 className="text-2xl font-bold text-slate-800">Government Schemes</h1>
        <p className="text-slate-500 text-sm">Post new schemes and announcements for SHGs</p>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="bg-[#FFF5F7] p-4 border-b border-[#FCE4EC] flex items-center gap-2">
          <PlusCircle className="w-5 h-5 text-[#C2185B]" />
          <h2 className="font-semibold text-[#880E4F]">Post New Scheme</h2>
        </div>
        <form onSubmit={handleSubmit} className="p-6 space-y-5">
          <div className="space-y-1.5">
            <Label htmlFor="title" className="text-gray-700">Scheme Title</Label>
            <Input
              id="title"
              placeholder="e.g. Mahila Samridhi Yojana"
              value={title}
              onChange={e => setTitle(e.target.value)}
              disabled={submitting}
              className="bg-gray-50 border-gray-200 focus:bg-white"
            />
          </div>

          <div className="space-y-1.5">
            <Label htmlFor="description" className="text-gray-700">Detailed Description</Label>
            <Textarea
              id="description"
              placeholder="Provide eligibility details, benefits, and application process..."
              rows={4}
              value={description}
              onChange={e => setDescription(e.target.value)}
              disabled={submitting}
              className="bg-gray-50 border-gray-200 focus:bg-white resize-y"
            />
          </div>

          <Button 
            type="submit" 
            className="bg-gradient-to-r from-[#C2185B] to-[#AD1457] hover:opacity-90 text-white"
            disabled={submitting}
          >
            {submitting ? 'Posting...' : 'Post Scheme to Network'}
          </Button>
        </form>
      </div>

      <div className="space-y-4">
        <h2 className="text-lg font-semibold text-slate-800">Previously Posted Schemes</h2>

        {loading ? (
          <div className="p-8 text-center text-slate-500">Loading schemes...</div>
        ) : schemes.length === 0 ? (
          <div className="bg-white p-8 text-center border border-dashed border-slate-200 rounded-xl text-slate-500">
            No schemes have been posted yet.
          </div>
        ) : (
          <div className="space-y-4">
            {schemes.map(scheme => (
              <div key={scheme.id} className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow">
                <div className="flex justify-between items-start gap-4">
                  <h3 className="font-bold text-lg text-slate-800 flex-1">{scheme.title}</h3>
                  <div className="bg-green-100 text-green-800 text-xs px-2.5 py-1 rounded-full font-medium whitespace-nowrap">
                    Active
                  </div>
                </div>

                <p className="text-slate-600 mt-3 text-sm whitespace-pre-wrap leading-relaxed">
                  {scheme.description}
                </p>

                <div className="mt-4 pt-4 border-t border-slate-100 flex flex-wrap items-center gap-4 text-xs text-slate-500">
                  <div className="flex items-center gap-1.5">
                    <FileText className="w-3.5 h-3.5" />
                    Posted by: {scheme.admin_email || 'Admin'}
                  </div>
                  <div className="flex items-center gap-1.5">
                    <Calendar className="w-3.5 h-3.5" />
                    Date: {new Date(scheme.created_at).toLocaleDateString()}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
